import type { Drill } from "./types";

// Service / early drills, keyed by module slug — 25 per module.
// Front-line service worker: retail associate, server, barista, hotel housekeeper, personal carer, cleaner, or security guard. Merged into course.ts.
export const SERVICE_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-svc-early-01","level":"early","profession":"service","title":"The shift-swap text that buries the ask","scenario":"You need someone to take your Saturday close because your cousin's wedding got moved. Your draft text to the group chat starts with the whole wedding story before the actual ask appears at the end.","task":"Write a 1-2 sentence group text that puts the swap request first.","tips":["First words: the shift you need covered, date and time.","One line of why is plenty — after the ask.","End with what you'll trade or take in return."],"focus":["clarity","concision"],"placeholder":"Can anyone take my Saturday close (4-11)?"},
    {"id":"lead-svc-early-02","level":"early","profession":"service","title":"Calling in sick without the saga","scenario":"You woke up with a fever and can't make your 7am shift. You're nervous, so your draft message to your shift manager walks through your whole night before saying you can't come in.","task":"Write a 2-3 sentence message that says you can't come in, in sentence one.","tips":["Lead with the fact: you can't make today's shift.","Then the practical bits: which shift, and whether you found cover.","Save the symptoms — one word is enough."],"focus":["clarity","structure"],"placeholder":"I can't come in for my 7am shift today — I'm sick."},
    {"id":"lead-svc-early-03","level":"early","profession":"service","title":"The espresso machine is down","scenario":"The espresso machine just stopped mid-steam and won't restart. The morning rush starts in 20 minutes. Your instinct is to text your manager everything you tried before saying the machine is dead.","task":"Write a text that leads with the problem and what you need.","tips":["First line: machine down, rush in 20 minutes.","The ask: call the repair line, or approve the backup plan?","What you already tried goes last, in one line."],"focus":["clarity","impact"],"placeholder":"Espresso machine is dead and the rush starts at 7 —"},
    {"id":"lead-svc-early-04","level":"early","profession":"service","title":"The spill call","scenario":"A jar of pasta sauce just smashed in aisle 5 and there's glass on the floor. You're radioing the front desk, but you tend to start with how it happened instead of what's needed.","task":"Say (or write) a one-sentence radio call that leads with the hazard and location.","tips":["Hazard and location first: glass and sauce, aisle 5.","Then the ask: someone to block the aisle while you get the kit.","How it happened can wait for later — or never."],"focus":["clarity","precision"],"placeholder":"Glass and sauce spill in aisle 5 — need someone to block it off while I grab the kit."},
    {"id":"lead-svc-early-05","level":"early","profession":"service","title":"The handover note that hides the one thing","scenario":"You're finishing your shift and writing the handover note. Most of it is routine, but the walk-in fridge has been running warm all afternoon and the evening crew must check it hourly. Your draft mentions that in the middle of a long list.","task":"Rewrite the handover so the fridge warning is the first line.","tips":["If they read only one line, it should be the fridge.","Routine items go below, grouped and short.","Say exactly what to do: check the temp every hour, log it."],"focus":["structure","impact"],"placeholder":"FIRST: walk-in fridge is running warm — check the temp every hour and log it."},
    {"id":"lead-svc-early-06","level":"early","profession":"service","title":"Escalating the unhappy guest","scenario":"A guest at table 9 found a hair in her salad and wants to speak to a manager. You're finding your manager in the back, but you tend to retell the whole conversation before saying what the guest wants.","task":"Say a 1-2 sentence handoff that leads with what the guest needs right now.","tips":["First sentence: table 9 wants a manager, hair in the salad.","Add the one detail that helps: she's calm but wants the meal replaced.","Skip the blow-by-blow of what was said."],"focus":["clarity","concision"]},
    {"id":"lead-svc-early-07","level":"early","profession":"service","title":"We're out of it — say so first","scenario":"A customer asks for the advertised air fryer. You checked this morning: sold out, next delivery Thursday. Your instinct is to explain the delivery schedule before admitting it's gone.","task":"Give a 2-sentence answer that says it's sold out first, then the option.","tips":["Answer first: we're sold out.","Then the helpful part: Thursday's delivery, or a rain check.","Don't make them wait through the backstory for the verdict."],"focus":["clarity","audience"],"placeholder":"We're sold out of that one, I'm sorry. The next delivery is Thursday —"},
    {"id":"lead-svc-early-08","level":"early","profession":"service","title":"The time-off request that circles","scenario":"You want the 12th to the 16th of next month off for a family trip. Your draft message to your manager opens with how you never ask for time off and how sorry you are to ask now.","task":"Write a 2-sentence request that puts the dates in sentence one.","tips":["Lead with the dates you need.","One line of context is fine — after the ask.","Offer what helps: you'll swap or find cover if needed."],"focus":["clarity","concision"],"placeholder":"Could I have the 12th-16th of next month off?"},
    {"id":"lead-svc-early-09","level":"early","profession":"service","title":"Something's happening at the back door","scenario":"You're on the floor and you've just watched someone slip two phone cases into their jacket and head toward the exit. You need to alert your manager now, but your instinct is to start with when you first noticed them browsing.","task":"Say a one-sentence alert that leads with what's happening right now.","tips":["Now first: person in the grey jacket heading to the exit with unpaid stock.","Location and description beat the timeline.","Follow store policy — alert, don't confront."],"focus":["clarity","precision"],"placeholder":"Grey jacket, heading for the main exit now — two phone cases in his pocket, unpaid."},
    {"id":"lead-svc-early-10","level":"early","profession":"service","title":"The room isn't ready","scenario":"You're housekeeping and room 214 needs a maintenance fix — the shower won't drain — so it can't be sold tonight. Front desk needs to know before the 3pm check-ins. Your draft note describes your whole cleaning round first.","task":"Write a 1-2 sentence note to front desk that leads with the room and its status.","tips":["First words: 214 is out of service — shower won't drain.","Then what's next: maintenance has been told, no ETA yet.","Your round summary belongs somewhere else."],"focus":["clarity","impact"],"placeholder":"Room 214 can't be sold tonight — shower won't drain."},
    {"id":"lead-svc-early-11","level":"early","profession":"service","title":"Calling the family after a fall","scenario":"You're a personal carer. Your client slipped in the kitchen this morning — she's fine, no injury, checked and comfortable. You need to tell her daughter, and you know the word 'fall' will scare her.","task":"Write the first two sentences of the call, leading with the reassurance and the fact together.","tips":["Lead with 'she's okay' in the same breath as what happened.","Then the specifics: when, where, what you checked.","Don't build suspense — that's what frightens people."],"focus":["audience","clarity"],"placeholder":"First, your mum is absolutely fine — she had a small slip in the kitchen this morning and there's no injury."},
    {"id":"lead-svc-early-12","level":"early","profession":"service","title":"Cover my break?","scenario":"You're due a break in ten minutes but the floor is busy and you need a coworker to cover your till. Your draft opens with an apology and a description of how long you've been standing.","task":"Write a one-sentence ask that leads with what you need and when.","tips":["The ask first: cover till 3 from 2:10 to 2:30.","Skip the apology — it's a normal request.","Make it easy to answer yes or no."],"focus":["concision","clarity"]},
    {"id":"lead-svc-early-13","level":"early","profession":"service","title":"The till is short","scenario":"You counted your register at close and it's short $20. Store policy says report it right away. Your draft message to your manager spends four sentences explaining how careful you always are before stating the number.","task":"Write a 2-3 sentence report that leads with the shortage.","tips":["First line: till 2 is short $20 at close.","Then the facts: you counted twice, when, and the day's till number.","Defending yourself up front reads worse than plain facts."],"focus":["clarity","precision"],"placeholder":"Till 2 came up $20 short at close — I counted twice."},
    {"id":"lead-svc-early-14","level":"early","profession":"service","title":"The damaged delivery","scenario":"This morning's produce delivery arrived with two crates of tomatoes crushed and leaking. The driver has already left. Your manager is off-site until noon and needs to know before the supplier's cutoff for claims at 11.","task":"Write a text that leads with the problem and the deadline.","tips":["Headline first: two crates crushed, claim cutoff at 11.","The ask: should you file the claim or wait?","Photos help — say you have them."],"focus":["impact","precision"],"placeholder":"Two crates of tomatoes arrived crushed — supplier claim cutoff is 11am."},
    {"id":"lead-svc-early-15","level":"early","profession":"service","title":"Can I return this? Answer first","scenario":"A customer holds up a kettle with a receipt from six weeks ago. Policy is 30 days, so the answer is no — but there's a repair option through the maker's warranty. You tend to explain the whole policy before giving the verdict.","task":"Give a 2-sentence answer that leads with the no, kindly, then the option.","tips":["Verdict first: it's past our 30-day window, so I can't refund it.","Immediately follow with the path: the maker's warranty covers it.","A clear no plus a real option beats a soft maybe."],"focus":["clarity","audience"]},
    {"id":"lead-svc-early-16","level":"early","profession":"service","title":"The security log that buries the incident","scenario":"You're a security guard writing your end-of-shift log. Eleven hours were quiet, but at 2:40am someone tried the loading-dock door. Your draft describes every quiet patrol round before mentioning it.","task":"Write the opening line of the log so the incident comes first.","tips":["Lead with the one thing that matters: attempted entry, loading dock, 2:40am.","Quiet rounds get one summary line, after.","Whoever reads the log skims — put the news on top."],"focus":["structure","precision"],"placeholder":"02:40 — attempted entry at the loading-dock door; handle tried twice, no access gained."},
    {"id":"lead-svc-early-17","level":"early","profession":"service","title":"The kitchen is backed up — tell the table now","scenario":"Table 12 ordered twenty minutes ago and the kitchen just told you their mains are another fifteen out. You're walking over. Your instinct is to open with a long apology instead of the number they actually want.","task":"Say 1-2 sentences that lead with the honest wait time.","tips":["The number first: about fifteen more minutes.","One short apology, not three.","Offer something concrete if you can — drinks topped up, bread out."],"focus":["clarity","audience"],"placeholder":"Your mains are about fifteen minutes out — I'm sorry for the wait."},
    {"id":"lead-svc-early-18","level":"early","profession":"service","title":"Asking for more hours","scenario":"You want to move from 15 to 25 hours a week, and you know Tuesday and Thursday evenings are short-staffed. Your draft message to your manager opens with a paragraph about your rent going up.","task":"Write a 2-3 sentence request that leads with the ask and where you'd fit.","tips":["Ask first: 10 more hours a week.","Then the part that helps them say yes: you can take Tue/Thu evenings.","Your reasons matter less than their gap — lead with the fit."],"focus":["clarity","impact"],"placeholder":"I'd like to pick up about 10 more hours a week — I can cover Tuesday and Thursday evenings."},
    {"id":"lead-svc-early-19","level":"early","profession":"service","title":"The vacuum needs replacing — say so","scenario":"The vacuum on your cleaning cart has lost suction for the third week running, and you're spending an extra ten minutes per floor. Your draft note to the supervisor recounts each breakdown in order before getting to what you want.","task":"Write a 2-sentence note that leads with the ask.","tips":["Ask first: this vacuum needs repair or replacement.","One line of evidence: third week of poor suction, ten extra minutes a floor.","History of every breakdown isn't needed — the pattern is."],"focus":["clarity","concision"]},
    {"id":"lead-svc-early-20","level":"early","profession":"service","title":"Running late — lead with the new time","scenario":"Your bus broke down and you'll be 25 minutes late for your shift. Your draft text to your manager tells the whole bus story first.","task":"Write a one-sentence text that leads with your arrival time.","tips":["The time first: I'll be there at 9:25.","Reason in three words, after.","Offer the fix if there is one: stay 25 late tonight."],"focus":["concision","clarity"],"placeholder":"I'll be in at 9:25 — bus broke down."},
    {"id":"lead-svc-early-21","level":"early","profession":"service","title":"The allergy call to the kitchen","scenario":"The guest on table 4 just told you she has a severe nut allergy, after you've already sent her order. You're heading to the pass to tell the kitchen. Every second of preamble is a second the dish gets closer to cooked.","task":"Say a one-sentence alert that leads with the allergy and the table.","tips":["Allergy, table, dish — in that order, immediately.","Then the ask: hold or remake the order.","This is the clearest case there is for point-first speaking."],"focus":["clarity","impact"],"placeholder":"Severe nut allergy on table 4 — hold the satay order, it needs a remake."},
    {"id":"lead-svc-early-22","level":"early","profession":"service","title":"The holiday-hours phone call","scenario":"A caller asks if you're open on the holiday Monday. You are, 10 to 4. You tend to walk callers through the whole week's schedule before answering the day they asked about.","task":"Give a one-sentence answer to the question asked, then stop.","tips":["Answer the asked day first: yes, 10 to 4 on Monday.","Only add the rest of the week if they ask.","Short answers respect the caller's time — and yours."],"focus":["concision","audience"]},
    {"id":"lead-svc-early-23","level":"early","profession":"service","title":"The loose handrail","scenario":"You noticed the handrail on the back stairs is loose — it moves a full inch when gripped. Staff use those stairs with armloads of stock all day. Your draft report opens with when you first thought something felt off.","task":"Write a 2-sentence hazard report that leads with the danger and the place.","tips":["First line: loose handrail, back stairs, moves an inch under a hand.","Then why it's urgent: staff carry stock down those stairs all day.","Ask for the specific fix: tape it off and call maintenance today."],"focus":["clarity","impact"],"placeholder":"The back-stairs handrail is loose — it shifts a full inch when you grip it."},
    {"id":"lead-svc-early-24","level":"early","profession":"service","title":"The standing schedule change","scenario":"You've enrolled in a Tuesday evening course for the next ten weeks and can't work Tuesday nights anymore. Your draft to your manager buries this in the third sentence, after two sentences about how much you love the job.","task":"Write a 2-3 sentence message that puts the schedule change first.","tips":["Lead with the change and the dates it covers.","Then soften: you can pick up another evening instead.","Managers plan rotas weeks out — the sooner the headline lands, the better."],"focus":["clarity","structure"],"placeholder":"Starting the 3rd, I can't work Tuesday evenings for ten weeks —"},
    {"id":"lead-svc-early-25","level":"early","profession":"service","title":"The new door code note","scenario":"The back-door keypad code changes tonight at 10, and anyone who doesn't know will be locked out with the bins. You're writing the note for the staff board, and your draft opens with why head office changed the policy.","task":"Write a 2-sentence staff note that leads with what changes and when.","tips":["First line: new code from 10pm tonight, and where to get it.","Why it changed is one short line — or nothing.","Write for the person skimming the board with their coat half on."],"focus":["clarity","concision"],"placeholder":"The back-door code changes at 10pm tonight — get the new one from the duty manager before you leave."}
  ],
  "start-with-the-audience": [
    {"id":"audience-svc-early-01","level":"early","profession":"service","title":"Explaining '86' to the new server","scenario":"It's the new server's second shift and you just told her table that the salmon is '86'd, dying on the pass, so push the special.' She nodded and clearly understood none of it. She has a table waiting for her right now.","task":"Re-explain in 2-3 plain sentences what she needs to do at her table.","tips":["Drop the kitchen slang — say what it means, not the code for it.","Tell her the action: apologize, say the salmon's gone, suggest the special.","New people nod instead of asking — assume the jargon didn't land."],"focus":["audience","clarity"],"placeholder":"We're out of salmon for the night. At your table, just say —"},
    {"id":"audience-svc-early-02","level":"early","profession":"service","title":"Why the pool is closed, in guest words","scenario":"The hotel pool is closed because the chlorine balance failed this morning's test and the water needs 24 hours to correct. A family in swimsuits is standing in front of you. They don't care about chemistry — they care about their afternoon.","task":"Give a 2-3 sentence explanation built around what they can do instead.","tips":["Lead with what matters to them: closed until tomorrow morning, here's what's open.","One plain-words reason — 'a water-quality check didn't pass' — no chemistry lecture.","Offer the alternative before they have to ask."],"focus":["audience","clarity"],"placeholder":"I'm sorry — the pool is closed until tomorrow morning for a water-quality issue. The kids' splash area at the gym next door is free for our guests —"},
    {"id":"audience-svc-early-03","level":"early","profession":"service","title":"The return policy, translated","scenario":"A frustrated customer wants to return worn shoes. The policy in your head is store language: 'unworn condition, original packaging, 30 days, proof of purchase.' Reciting it at her will feel like a wall.","task":"Explain in 2-3 sentences what she can actually do from here.","tips":["Start from her options, not the rulebook.","Translate each policy term into a concrete step she can take.","Keep the tone on her side: 'here's what will work' beats 'here's what you did wrong.'"],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-04","level":"early","profession":"service","title":"The medication schedule for the family","scenario":"You're a carer, and your client's son is taking over for the weekend. Your handover sheet says 'Metformin 500mg BD with food, Ramipril 2.5mg OD mane.' He's an accountant, not a nurse, and he looks worried.","task":"Rewrite the medication instructions in 2-3 sentences a family member can follow.","tips":["Translate the shorthand: twice a day with meals, once each morning.","Anchor to his weekend: breakfast and dinner, not 'BD'.","Tell him the one thing to never skip and who to call with questions."],"focus":["audience","precision"],"placeholder":"Two medicines this weekend. The white one (Metformin) is one tablet with breakfast and one with dinner —"},
    {"id":"audience-svc-early-05","level":"early","profession":"service","title":"First till lesson, zero assumptions","scenario":"You're showing a brand-new hire the register. You've done these steps a thousand times, so you naturally say things like 'just void it and re-ring' and 'key in the PLU.' He started today and doesn't know what a PLU is.","task":"Explain how to fix a wrong item scan in 2-3 sentences a first-day hire can follow.","tips":["Beat the curse of knowledge: name the buttons, not the slang.","One step per sentence, in the order his hands will move.","Tell him what he'll see on screen when it worked."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-06","level":"early","profession":"service","title":"Your room isn't ready — frame it forward","scenario":"A guest arrives at 1pm; check-in is 3pm and her room is genuinely not ready. You could explain housekeeping schedules and checkout times. She's been traveling since 5am with two bags and a toddler.","task":"Say 2-3 sentences framed entirely around what she can do right now.","tips":["Her needs first: bags stored, somewhere to sit, when to come back.","Give a real time, not 'shortly.'","The housekeeping explanation is your context, not hers — skip it."],"focus":["audience","impact"],"placeholder":"Your room will be ready at 3, and I can take your bags right now so you're free —"},
    {"id":"audience-svc-early-07","level":"early","profession":"service","title":"The shelf price and the register price","scenario":"A customer's cereal rang up at $6.49 but the shelf said $4.99. The real cause: last week's promo label wasn't taken down. She doesn't want the supply-chain story — she wants to know what she'll pay.","task":"Give a 2-sentence explanation that answers her real question first.","tips":["Lead with the outcome: you'll pay the shelf price, I'll fix it now.","One-line reason in plain words: an old sale label was left up.","Own it simply — 'we missed that label' — without a speech."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-08","level":"early","profession":"service","title":"Same broken freezer, two audiences","scenario":"The gelato freezer died overnight. You need to tell your shift manager, who has to act, and you've caught yourself drafting the same words you'd say to a customer asking where the gelato went.","task":"Write the 2-sentence version for your manager — what she needs to decide, not what a customer needs to hear.","tips":["Manager's stake: stock at risk, money, and a decision — move it or call repair.","Include what a customer version would leave out: temps, timing, what's salvageable.","One audience per message; write this one only for her."],"focus":["audience","precision"],"placeholder":"The gelato freezer failed overnight — it's at 8°C and stock is at risk."},
    {"id":"audience-svc-early-09","level":"early","profession":"service","title":"The loyalty program without the app-speak","scenario":"An older customer asks about the loyalty program. The script says 'download the app, enable notifications, and scan your QR at checkout.' She has a flip phone in her hand.","task":"Explain in 2-3 sentences how she can join and benefit in a way that works for her.","tips":["Start from what she has: a phone number or a paper card works too.","Say the benefit in her terms: money off her shop, not 'points ecosystem.'","If a step won't work for her, don't mention it — offer the path that will."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-10","level":"early","profession":"service","title":"The bag check, explained to an annoyed visitor","scenario":"You're on security at a venue entrance and a visitor is bristling at the bag check: 'Why? I come here every week.' The real reason is a new policy after an incident, but a lecture will make it worse.","task":"Say 1-2 sentences that explain the check in terms of his stake, not the policy's.","tips":["His stake: it keeps the event safe for everyone including him, and takes ten seconds.","Skip the incident history — that's your context, not his.","Warm and brief beats thorough and defensive."],"focus":["audience","concision"],"placeholder":"It's a quick ten-second check we do for everyone now — it keeps the night safe for you too."},
    {"id":"audience-svc-early-11","level":"early","profession":"service","title":"Directions without insider landmarks","scenario":"A coworker from another branch is covering a shift and asks where the spare till rolls are. Your instinct: 'back of house, past the cage, in the old bakery cupboard.' She's never set foot in your building.","task":"Give directions in 2-3 sentences using only what a first-time visitor can see.","tips":["Use landmarks she can see: doors, signs, colors — not nicknames.","Start from where she's standing.","Count things: 'second door on the left' beats 'past the cage.'"],"focus":["audience","precision"]},
    {"id":"audience-svc-early-12","level":"early","profession":"service","title":"Why the drink takes longer","scenario":"A customer asks why her oat-milk latte is taking longer than her friend's regular one. The truth involves steaming temperatures and a separate jug for allergens. She just wants to know it's normal and how long.","task":"Answer in 1-2 sentences pitched to what she cares about.","tips":["Lead with the answer: about two more minutes, and it's normal.","One phrase of reason: oat milk steams differently and gets its own clean jug.","The allergen detail is actually reassuring — one mention, no lecture."],"focus":["audience","concision"],"placeholder":"About two more minutes — oat milk steams a little differently and we use a separate jug for it."},
    {"id":"audience-svc-early-13","level":"early","profession":"service","title":"The note left in the guest's room","scenario":"You're housekeeping and you had to move a guest's laptop and papers off the bed to change the sheets. Guests can panic when their things have moved. You're leaving a short note.","task":"Write a 1-2 sentence note that tells the guest what they'll want to know at a glance.","tips":["Answer their first fear immediately: nothing is missing, items were moved to the desk.","Say who and why in a few words: housekeeping, to change the bedding.","Sign it so it feels human, not anonymous."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-14","level":"early","profession":"service","title":"The menu answer for a coeliac guest","scenario":"A guest says she's coeliac and asks about the fish and chips. You know the kitchen's answer: the fryer is shared with battered items, so nothing fried is safe, but the grilled fish is prepared separately. She needs the answer in her terms: what can I safely eat?","task":"Answer in 2-3 sentences built around her safe choices.","tips":["Lead with what IS safe for her, then what isn't and why in plain words.","'Shared fryer' matters to her — say it simply, it's the honest detail she needs.","Offer to double-check with the kitchen; for allergies, certainty beats speed."],"focus":["audience","precision"],"placeholder":"The fish and chips won't be safe — the fryer is shared with battered items. But the grilled fish is done separately, and —"},
    {"id":"audience-svc-early-15","level":"early","profession":"service","title":"Why the order is late — the caller's version","scenario":"A caller asks why her click-and-collect order isn't ready. Internally: the picking team is two people down and the system queued her order behind forty others. She cares about one thing — when can she come?","task":"Give a 2-sentence answer to the question she's actually asking.","tips":["Lead with a real time she can plan around.","'We're short-staffed today' is enough reason — the queue math is internal.","Offer the practical extra: we'll text you the moment it's ready."],"focus":["audience","concision"]},
    {"id":"audience-svc-early-16","level":"early","profession":"service","title":"Self-checkout for the first-timer","scenario":"A customer is frozen in front of the self-checkout, holding a basket, looking embarrassed. You use these machines all day and could recite the flow in your sleep — which is exactly the danger.","task":"Talk her through the first two steps in 2-3 sentences a first-time user can follow.","tips":["Start at her first action: scan the barcode — and say where the barcode is.","One step at a time; wait for each to land.","Name what the machine will do so it doesn't surprise her: it beeps, the price appears."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-17","level":"early","profession":"service","title":"The closing checklist for someone's first close","scenario":"A coworker is doing his first-ever close tonight and you're leaving at 9. The list in your head is shorthand: 'drop the float, flip the fryers, set the alarm on your way out.' None of those words mean anything to him yet.","task":"Write the three most important closing steps in newcomer language, one sentence each.","tips":["Expand every shorthand: what the float is, where it goes.","Order matters — write them in the order he'll do them.","Flag the one step that must never be skipped, and what happens if it is."],"focus":["audience","structure"],"placeholder":"1. Count the cash drawer and put $150 back in — the rest goes in the grey pouch into the safe (under the counter, code on the key tag)."},
    {"id":"audience-svc-early-18","level":"early","profession":"service","title":"Card machine down — what the customer should do","scenario":"The card machines just went down storewide. You're telling each customer at the till. The IT explanation is a network outage with no ETA; the customer's question is 'how do I pay for this?'","task":"Say 1-2 sentences that give customers their options first.","tips":["Options first: cash works, and the ATM by the door is free.","'Card payments are down for the moment' — that's all the diagnosis they need.","Say what you'll do for them: hold the basket at the desk while they get cash."],"focus":["audience","clarity"],"placeholder":"Card payments are down right now — cash still works, and there's a free ATM by the entrance."},
    {"id":"audience-svc-early-19","level":"early","profession":"service","title":"Preparing your client for a new face","scenario":"You're a carer and next week a different carer covers your holiday. Your client gets anxious about strangers in her home. Telling her 'agency staffing rotation' anything will make it worse.","task":"Tell her about the change in 2-3 sentences pitched to what reassures her.","tips":["Anchor to what stays the same: same times, same routine, same tea order.","Introduce the person, not the arrangement: her name is Priya, she's lovely, I've briefed her on everything.","Give her control where you can: your daughter has Priya's number."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-20","level":"early","profession":"service","title":"The section change, framed for the manager","scenario":"You've strained your ankle and need to work the smaller section near the kitchen tonight instead of the far patio. Your draft is all about your ankle. Your manager's actual problem is covering the patio.","task":"Write a 2-sentence request framed around the coverage problem, not just your ankle.","tips":["Pair the ask with the solution: swap sections with Dana, who already offered.","The manager's stake is the floor plan — address it in sentence one or two.","Keep the medical detail to five words."],"focus":["audience","impact"],"placeholder":"Could I take section 2 tonight instead of the patio? Dana's happy to swap —"},
    {"id":"audience-svc-early-21","level":"early","profession":"service","title":"Translating the supplier notice for the team","scenario":"A supplier email says: 'SKUs 4471-4489 are on allocation through Q3 due to upstream constraints.' Your team needs to know what to tell customers who ask for those products — which are the popular garden chairs.","task":"Write a 2-sentence note for the staff board translating the notice into shop-floor terms.","tips":["Name the products the way staff and customers do — not SKU numbers.","Say what to tell a customer: limited stock until September, no holds.","What staff should DO matters more than why it happened."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-22","level":"early","profession":"service","title":"Click-and-collect, explained on the phone","scenario":"A caller has never used click-and-collect and wants to know how it works. You know the internal flow: order online, wait for the 'ready' notification, come to the collection desk with ID. She keeps asking 'so I just... come in?'","task":"Explain the process in 2-3 sentences from her side of the counter.","tips":["Walk her timeline, not the system's: order today, wait for the text, then come in.","Name the one thing people forget: bring the card you paid with.","Check the landing: 'does that make sense?' is fine on a call."],"focus":["audience","structure"],"placeholder":"You order on our website, and we text you when it's ready — usually within two hours."},
    {"id":"audience-svc-early-23","level":"early","profession":"service","title":"Two room types, in the guest's terms","scenario":"A guest at the desk asks the difference between the Standard and the Deluxe. The rate sheet says '6 sqm larger, upper floors, enhanced amenities.' She's deciding whether the extra $40 is worth it for two nights with her husband.","task":"Explain the difference in 2-3 sentences that help her decide.","tips":["Translate specs into experience: quieter high floor, a proper armchair, the good shower.","Anchor to her stay: for two nights, here's what you'd actually notice.","Give an honest steer if she asks — guests trust a straight answer."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-24","level":"early","profession":"service","title":"The tip pool, explained straight","scenario":"A new server just got her first payslip and quietly asks why her card tips look smaller than she expected. The tip pool is fair but nobody ever explained it: all tips are shared by hours worked, with a share to the kitchen.","task":"Explain the tip pool in 2-3 sentences that leave her trusting the system.","tips":["Lead with the principle in plain words: everyone's tips go in one pot, split by hours.","Use her payslip as the example — walk one real number through.","Tell her where the full breakdown lives so she can check any week herself."],"focus":["audience","clarity"]},
    {"id":"audience-svc-early-25","level":"early","profession":"service","title":"The sign customers will actually read","scenario":"The main entrance is closed for repairs for three days and customers must use the side door on Elm Street. The draft sign from head office reads: 'Due to scheduled maintenance operations, ingress has been temporarily relocated.' People will walk past it.","task":"Rewrite the sign in one or two short lines a hurrying customer can absorb.","tips":["Say the action first: Use the Elm Street door (20 steps to your left).","An arrow does more than a paragraph.","Cut 'due to' entirely — nobody needs the reason to find a door."],"focus":["audience","concision"],"placeholder":"Please use our Elm Street door — 20 steps to your left. →"}
  ],
  "structure-that-carries": [
    {"id":"structure-svc-early-01","level":"early","profession":"service","title":"Nine scattered items, one handover","scenario":"Your end-of-shift handover has nine items in the order you remembered them: a broken tap, two customer holds, low till roll, a complaint to follow up, a delivery due, a lost umbrella, a fridge temp check, and two staff messages. The next shift reads it standing up, in one minute.","task":"Group the nine items into 2-3 labeled buckets and write the bucket headings with one item under each.","tips":["Group by what the reader must DO: fix/watch, customer follow-ups, FYI.","Urgent bucket first, always.","A label like 'Needs action tonight' does half the work of the note."],"focus":["structure","clarity"],"placeholder":"NEEDS ACTION TONIGHT: fridge temp check at 8pm —"},
    {"id":"structure-svc-early-02","level":"early","profession":"service","title":"'How was the shift?' — answered with PREP","scenario":"Your manager catches you at the door: 'How was the shift?' You have a real answer — busy lunch, one complaint handled, and the card machine glitched twice — but it usually comes out as a jumble.","task":"Give a spoken 4-sentence answer using PREP: point, reason, example, point.","tips":["Point first: 'Good shift overall, one thing to flag.'","The example is your evidence — one concrete moment, not three.","Land back on the point so she leaves with your headline, not your last detail."],"focus":["structure","concision"],"placeholder":"Good shift overall — one thing worth flagging."},
    {"id":"structure-svc-early-03","level":"early","profession":"service","title":"The incident report skeleton","scenario":"A customer slipped near the drinks fridge an hour ago. She's fine, declined first aid, and you mopped and signed the area. Now you're filling in the incident form, and your draft is one long paragraph mixing everything together.","task":"Rewrite as four short labeled parts: what happened, when and where, who was involved, what you did.","tips":["One fact per sentence — reports get read by people who weren't there.","Times and places exact: 2:15pm, drinks fridge aisle, not 'earlier, near the back.'","What you did after matters as much as what happened — give it its own line."],"focus":["structure","precision"],"placeholder":"WHAT HAPPENED: A customer slipped on a wet patch by the drinks fridge."},
    {"id":"structure-svc-early-04","level":"early","profession":"service","title":"The new-equipment ask, built to carry","scenario":"You want the café to buy a second blender. Your reasons are real: the single blender queues smoothie orders, it overheats on hot days, and you lose walk-outs waiting. Right now your pitch is those facts in random order.","task":"Structure a 4-5 sentence pitch: the ask, then your 2-3 reasons as clear separate points, then the ask again.","tips":["One governing idea: a second blender pays for itself — everything hangs off it.","Give each reason its own sentence; don't let them blur together.","Close by repeating the ask with a next step: can I get a price for approval?"],"focus":["structure","impact"]},
    {"id":"structure-svc-early-05","level":"early","profession":"service","title":"A week of complaints, three themes","scenario":"Your manager asked what customers complained about this week. You have seven: cold coffee twice, a rude delivery driver, slow weekend service three times, and a wrong price label. Listing all seven in order tells her nothing.","task":"Group the complaints into themes and write a 3-sentence summary, one theme per sentence, biggest first.","tips":["Count inside each theme: 'slow weekend service, 3 of 7' is the headline.","Lead with the theme you'd fix first.","Seven data points, three ideas — that's the compression the reader needs."],"focus":["structure","precision"],"placeholder":"Three themes this week — the biggest is weekend speed: 3 of 7 complaints were about wait times on Saturday."},
    {"id":"structure-svc-early-06","level":"early","profession":"service","title":"SCQA for the closing-routine change","scenario":"You think the close would go faster if the floor clean started an hour before closing instead of after the doors lock. You want to propose it to your manager, and you've heard that starting with the situation everyone agrees on works better than opening with the idea cold.","task":"Write a 4-sentence proposal: situation, complication, question, answer.","tips":["Situation: something she already knows is true — closes run to 11:30.","Complication: what's changed or what it costs — overtime every Friday.","Let the question surface naturally, then your answer is the fix."],"focus":["structure","clarity"],"placeholder":"Right now the floor clean starts after the doors lock at 10."},
    {"id":"structure-svc-early-07","level":"early","profession":"service","title":"Three asks, one message — or three?","scenario":"You're messaging your manager about three unrelated things: next month's availability, a broken hand dryer, and a question about the staff discount. Your draft mixes all three into two long paragraphs where each ask half-hides.","task":"Restructure into one message with three labeled parts — or explain in one line which you'd split out and why.","tips":["Unrelated asks need visible seams: numbers or bold labels.","Put the time-sensitive one first.","If one item needs a different person or a conversation, split it off."],"focus":["structure","clarity"]},
    {"id":"structure-svc-early-08","level":"early","profession":"service","title":"The opening checklist, in walking order","scenario":"You're writing the morning opening steps for a new hire: lights, tills, coffee machine warm-up, chairs down, sandwich delivery check, door unlock at 8. Your draft lists them in the order you thought of them, which sends him zigzagging across the shop.","task":"Rewrite the checklist in the order his feet and the clock actually demand, one line per step.","tips":["Sequence by dependency: the machine warms up for 20 minutes — start it first.","Group by location so he isn't crossing the shop five times.","Put the time-critical step (unlock at 8) as its own bold final line."],"focus":["structure","clarity"]},
    {"id":"structure-svc-early-09","level":"early","profession":"service","title":"The swap request with a built-in plan","scenario":"You need next Friday off. A bare 'can I have Friday off?' makes your manager do all the work. You've already found that Marco can cover, and you can take his Sunday in return.","task":"Write a 3-sentence request structured as: the ask, the cover plan, the fallback.","tips":["Ask first, then immediately show you've solved her problem.","Name names: Marco has agreed — not 'someone could probably cover.'","A fallback ('if that doesn't work, I could…') shows you thought past step one."],"focus":["structure","impact"],"placeholder":"Could I have next Friday off? Marco's agreed to cover my shift —"},
    {"id":"structure-svc-early-10","level":"early","profession":"service","title":"The busy night, summarized for the boss who was off","scenario":"Saturday was chaos: a 45-minute kitchen backlog, a comped table, a broken glass washer, record covers, and a new hire who did well. Your manager, back Monday, asks how it went. You could talk for ten minutes — she has two.","task":"Give a spoken summary: one headline sentence, then three grouped points.","tips":["Headline: the one sentence that frames it — 'record night, and the kitchen bottleneck cost us.'","Group: what went well, what broke, what needs her decision.","End on the item that needs her action, so it sticks."],"focus":["structure","concision"],"placeholder":"Record covers Saturday — but the kitchen backlog is the thing to talk about."},
    {"id":"structure-svc-early-11","level":"early","profession":"service","title":"Lost property, step by step","scenario":"Guests keep asking staff what happens to items left in hotel rooms, and everyone gives a different answer. You've been asked to write the short version for the front-desk binder: log it, tag it, store 90 days, post at guest's cost on request.","task":"Write the process as 3-4 ordered steps a colleague could read aloud to a guest.","tips":["Order by the guest's timeline: found, logged, stored, returned.","One action per step, starting with a verb.","End with the step the guest cares most about: how to get it back."],"focus":["structure","clarity"]},
    {"id":"structure-svc-early-12","level":"early","profession":"service","title":"Three rota problems, one governing idea","scenario":"The new rota gives you three problems: two closes back-to-back with a 7am open between them, your fixed Tuesday class ignored, and only 12 hours total when you're contracted for 20. Fired off separately, they sound like three complaints. Together they say one thing: the rota didn't use your availability form.","task":"Write a 3-4 sentence message that leads with the governing idea and hangs the three issues under it.","tips":["Find the single sentence that explains all three problems — lead with it.","List the three as short, parallel points.","End with the fix: re-run my shifts against the form I submitted."],"focus":["structure","clarity"],"placeholder":"I think my availability form got missed in this rota — three things point that way."},
    {"id":"structure-svc-early-13","level":"early","profession":"service","title":"The fire-drill debrief","scenario":"Today's evacuation drill mostly worked, but you noticed three things as floor marshal: the back corridor bottlenecked, two staff didn't know the assembly point, and the alarm wasn't audible in the cold room. You're reporting to the duty manager.","task":"Structure a spoken debrief: overall verdict first, then the three findings in order of risk.","tips":["Verdict first: 'the drill worked, with three fixes needed.'","Order findings by danger, not by when you noticed them.","Attach a suggested fix to each finding — a half-sentence each."],"focus":["structure","impact"],"placeholder":"Overall the drill worked — everyone was out in four minutes — but I found three things."},
    {"id":"structure-svc-early-14","level":"early","profession":"service","title":"'Why are kiosk sales down?' — a structured answer","scenario":"The manager asks why the coffee kiosk's takings dropped this month. You know pieces: the office block next door is half-empty for renovations, the card reader was down four mornings, and the new menu dropped the bestselling toastie. Unstructured, it sounds like excuses.","task":"Give a 4-sentence spoken answer: your one-line reading, then the three causes as separate points.","tips":["Lead with your reading: 'mostly footfall, plus two things we control.'","Separate what you can fix from what you can't — that's the useful grouping.","Numbers where you have them: four mornings, the toastie was our #1."],"focus":["structure","precision"]},
    {"id":"structure-svc-early-15","level":"early","profession":"service","title":"The supply list that orders itself","scenario":"You're leaving the weekly supplies note: gloves, blue roll, glass cleaner, mop heads, bin liners, descaler, and the fancy hand soap for the customer toilets. Written as one comma chain, things get missed.","task":"Rewrite the list grouped so the person ordering can work through it without missing anything.","tips":["Group by supplier or by where it's used — pick one logic and hold it.","Flag quantities and the truly-out items: 'OUT: gloves (medium).'","A grouped list is a checklist; a comma chain is a memory test."],"focus":["structure","precision"]},
    {"id":"structure-svc-early-16","level":"early","profession":"service","title":"The recurring problem, made into a case","scenario":"The milk fridge has now failed three times in two weeks — you've got dates and what it cost each time (spoiled stock twice, an emergency milk run once). Each time it was reported as a one-off. You want your manager to see the pattern.","task":"Write a 3-4 sentence message structured as: pattern, evidence, cost, ask.","tips":["Name the pattern in sentence one — 'three failures in two weeks' is the story.","Dates in one tidy list, not scattered through prose.","End with a specific ask: replace it, or get a tech out this week."],"focus":["structure","precision"],"placeholder":"The milk fridge has failed three times in two weeks — this is a pattern, not a one-off."},
    {"id":"structure-svc-early-17","level":"early","profession":"service","title":"The local tips, organized by what they asked","scenario":"Hotel guests ask you for area recommendations, and you tend to fire off everything you love in one breath — tacos, the gallery, the night market, the ferry. A couple just asked: 'We have one free evening. What should we do?'","task":"Give a spoken answer structured around their one evening: a first pick, a backup, and one practical note.","tips":["Their constraint (one evening) is your structure — don't list the whole city.","Lead with your best single pick and why it fits an evening.","One practical note (book ahead, last ferry at 10) makes it usable."],"focus":["structure","audience"]},
    {"id":"structure-svc-early-18","level":"early","profession":"service","title":"The near-miss report","scenario":"A stack of chairs nearly fell on a coworker in the storeroom this morning — caught just in time, nobody hurt. Near-misses are supposed to be reported so the real accident never happens. Your draft reads like a story: 'So Jamie was getting the chairs and…'","task":"Write the near-miss in report structure: what nearly happened, why it nearly happened, what will stop it next time.","tips":["'What nearly happened' takes one plain sentence — resist the storytelling.","The cause matters most: chairs stacked above the safe height against a slanted wall.","The fix is the point of the report — make it concrete and last."],"focus":["structure","precision"],"placeholder":"NEAR-MISS: A stack of chairs tipped in the storeroom and nearly struck Jamie — no injury."},
    {"id":"structure-svc-early-19","level":"early","profession":"service","title":"Your availability, scannable in five seconds","scenario":"The manager builds next month's rota tomorrow and asked everyone to send availability. Your situation has wrinkles: normal weeks except the 8th-10th away, no Tuesday evenings anymore, and you want extra hours in the last week. A paragraph will get skimmed and half-missed.","task":"Write your availability as a short structured message the manager can transfer to the rota without re-reading.","tips":["Three labeled lines: CAN'T, CAN, WANT.","Dates in numbers, days named — no 'the week after next.'","The format is the favor: she has fifteen of these to process."],"focus":["structure","concision"],"placeholder":"CAN'T: 8th-10th (away); Tuesday evenings (class, ongoing)."},
    {"id":"structure-svc-early-20","level":"early","profession":"service","title":"The no-receipt refund, in steps","scenario":"A customer wants to return a gift with no receipt. There IS a path — gift-card refund at the current price with ID — but you always explain it in a tangle and customers get confused about what happens when.","task":"Explain the process in 3 ordered steps, in the order the customer will experience them.","tips":["Sequence from her side: what she shows, what you do, what she walks out with.","One step per sentence.","Name the outcome plainly at the end: a gift card for today's price, not cash."],"focus":["structure","audience"]},
    {"id":"structure-svc-early-21","level":"early","profession":"service","title":"The cleaning round, regrouped","scenario":"Your office-cleaning checklist lists tasks by type: all bins, then all vacuuming, then all glass — which means three full laps of a four-floor building every night. You want to propose reorganizing it by floor.","task":"Write a 3-sentence proposal to your supervisor: the change, the reason, the result.","tips":["The change in one sentence: finish each floor completely before moving on.","Reason with a number: three laps becomes one, saving about 40 minutes.","Anticipate the check: quality stays — same tasks, new order."],"focus":["structure","impact"],"placeholder":"I'd like to switch the checklist from task order to floor order — do everything on floor 1, then move up."},
    {"id":"structure-svc-early-22","level":"early","profession":"service","title":"SCQA for moving the pastry case","scenario":"You're convinced the pastry case should move next to the till: people queue past it, impulse buys are being missed, and the current spot by the door gets morning glare that melts the glazes. You have one shot at pitching the owner between deliveries.","task":"Write a 4-sentence SCQA pitch: situation, complication, question, answer.","tips":["Situation: the layout as she knows it — no argument yet.","Complication: what it's costing — melted glazes and missed impulse sales.","Your answer includes the effort: one hour with two of us, done before open."],"focus":["structure","impact"]},
    {"id":"structure-svc-early-23","level":"early","profession":"service","title":"Training gaps, reported without blame","scenario":"Three new hires in a row have struggled with the same things: nobody showed them the allergen folder, the returns process, or where the safety kit lives. You want to tell the manager the training has holes — as one organized observation, not a moan.","task":"Write a 3-4 sentence note: the pattern, the three gaps as a list, and a suggested fix.","tips":["Frame as pattern, not blame: 'three hires, same three gaps.'","List the gaps in parallel form so they read as one problem.","Offer the cheap fix: a one-page first-week checklist — you'll draft it."],"focus":["structure","clarity"],"placeholder":"I've noticed the last three new hires hit the same three gaps in their first week."},
    {"id":"structure-svc-early-24","level":"early","profession":"service","title":"The voicemail with a spine","scenario":"You need to leave a voicemail for the maintenance contractor about the staff-toilet leak. Your last voicemail to them rambled for a minute and they called back asking for the address. This one needs a structure they can act on from a single listen.","task":"Script a 4-sentence voicemail: who and where, the problem, the urgency, the callback.","tips":["Identify first: name, business, street address — before the problem.","One sentence of problem, one of urgency: water reaching the storeroom wall.","Say the callback number slowly, then repeat it — the classic voicemail failure is the number."],"focus":["structure","clarity"]},
    {"id":"structure-svc-early-25","level":"early","profession":"service","title":"'Should we keep the late hours?' — PREP aloud","scenario":"The store trialed staying open to 9pm for a month, and the manager asks the closers point-blank in the team huddle: keep it or kill it? You closed most of those shifts and think the answer is no — the last hour was dead except Fridays.","task":"Give a spoken PREP answer: point, reason, example, point restated — under 30 seconds.","tips":["Point: 'Drop it, except Fridays.' — nuance can live inside a clear verdict.","Reason with your best number: most nights, fewer than five customers after 8.","Restate the point with the action: keep Friday late hours, close at 8 otherwise."],"focus":["structure","concision"],"placeholder":"I'd drop the late hours except Fridays."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-svc-early-01","level":"early","profession":"service","title":"The hedge-heavy swap text","scenario":"Your draft to a coworker reads: 'Hey! So sorry to bother you, I was just wondering if there was maybe any chance you could possibly take my Sunday shift? Totally fine if not, no worries at all!' The actual request is nine of those words.","task":"Rewrite the text with every hedge and softener cut, keeping it friendly.","tips":["'I was just wondering if maybe' → 'Can you.'","One 'no problem if not' is politeness; three is noise.","Friendly lives in tone and a thank-you, not in padding."],"focus":["concision","clarity"],"placeholder":"Can you take my Sunday shift (10-4)? Happy to trade."},
    {"id":"concise-svc-early-02","level":"early","profession":"service","title":"The apology that won't land","scenario":"A guest's breakfast order was forgotten and you're writing a note to leave with the comped meal. Your draft is six sentences of escalating apology — 'we sincerely and deeply regret' — and the guest will trust it less with every line.","task":"Cut the note to two sentences: one clean apology, one concrete amend.","tips":["One sincere sentence beats six escalating ones.","The amend is the apology: breakfast is on us today.","Cut every intensifier — 'sincerely, deeply, truly' — plain sorry reads truest."],"focus":["concision","impact"],"placeholder":"We're sorry we missed your breakfast order this morning."},
    {"id":"concise-svc-early-03","level":"early","profession":"service","title":"The radio call, trimmed to airtime","scenario":"Your radio call ran: 'Um, hi, it's me over in the east wing, sorry to interrupt, I was just doing my round and I noticed that it looks like one of the fire doors, the one near the lifts, seems to have been propped open by someone.' Radio channels are shared — every extra second blocks someone else.","task":"Cut the call to one sentence with position, problem, and nothing else.","tips":["Radio format: who, where, what — done.","'It looks like it seems to have been' is one word: 'is.'","If it needs action, say the action; otherwise release the channel."],"focus":["concision","precision"],"placeholder":"East wing: fire door by the lifts is propped open — closing it now."},
    {"id":"concise-svc-early-04","level":"early","profession":"service","title":"The whiteboard essay","scenario":"The staff whiteboard note you drafted has five lines: 'Hi team! Just a quick note to let everyone know that going forward, when you finish with the steam wand, if you could give it a quick wipe with the blue cloth that would be amazing, thanks so much!!' It's a one-line instruction wearing a coat.","task":"Rewrite the note in ten words or fewer.","tips":["Instructions on a board: verb first, no greeting.","'Going forward' and 'just a quick note' carry zero meaning.","One exclamation mark maximum — it's a wall, not a text."],"focus":["concision","clarity"],"placeholder":"Wipe the steam wand after every use (blue cloth)."},
    {"id":"concise-svc-early-05","level":"early","profession":"service","title":"'Sorry to bother you' — cut the opener","scenario":"Every message you send your shift manager starts with 'Sorry to bother you, I know you're really busy, but…' She's told you twice it's fine to just ask. Today's question: can you approve a price override for a damaged item?","task":"Write the message with the ask first and zero apology.","tips":["A normal work question needs no apology — asking IS the job.","'Quick question:' is an acceptable two-word runway; 'sorry to bother you' isn't.","Notice the habit: if every message apologizes, none of them means it."],"focus":["concision","clarity"]},
    {"id":"concise-svc-early-06","level":"early","profession":"service","title":"The 60-second voicemail, cut to 20","scenario":"You listened back to the voicemail you left the linen supplier: a minute long, your point (double next week's towel order) arrives at second 40, and you say 'like I said' twice. They deal with fifty hotels — long voicemails get skimmed or skipped.","task":"Script the same voicemail in 20 seconds or less.","tips":["Order: who you are, the ask, the number. Nothing else.","Cut every 'like I said' — say it once, correctly.","Read it aloud with a timer; 20 seconds is about 50 words."],"focus":["concision","structure"],"placeholder":"Hi, it's Sam at the Grandview Hotel. Please double next week's towel order —"},
    {"id":"concise-svc-early-07","level":"early","profession":"service","title":"The handover novel","scenario":"Your handover notes have grown to a full page: every task done, every non-event ('bins were fine, nothing to report on bins'), each with a sentence of context. The evening crew has started skipping them — which means they'll miss the one line that matters someday.","task":"Set a rule for yourself and rewrite tonight's handover to fit five lines.","tips":["Report exceptions, not routine: 'nothing to report' items are cuttable by definition.","One line per item: fact plus action.","If everything is included, nothing stands out — brevity is what makes the urgent line visible."],"focus":["concision","structure"]},
    {"id":"concise-svc-early-08","level":"early","profession":"service","title":"'Please kindly be advised' — the sign","scenario":"The draft sign for the café counter reads: 'Please kindly be advised that due to unforeseen circumstances we are currently experiencing a temporary shortage of oat milk at this present moment in time. We apologize for any inconvenience this may cause.' Thirty-one words for a four-word fact.","task":"Rewrite the sign in eight words or fewer.","tips":["'At this present moment in time' = 'today' — or nothing.","Customers need the fact and the alternative, not the apology essay.","Short signs get read; long signs get walked past."],"focus":["concision","audience"],"placeholder":"No oat milk today — soy and almond available."},
    {"id":"concise-svc-early-09","level":"early","profession":"service","title":"The incident report throat-clear","scenario":"Your incident report begins: 'I would like to take this opportunity to report that during the course of my shift this evening, an incident occurred which I feel I should bring to your attention, namely that…' The incident — a guest fainted in the lobby — hasn't appeared yet.","task":"Cut the opening so the first sentence IS the incident.","tips":["'I would like to report that X happened' = 'X happened.'","Meta-commentary ('I feel I should mention') defers the news — delete it.","Reports are read in emergencies and audits; both reward bluntness."],"focus":["concision","clarity"],"placeholder":"At 7:20pm a guest fainted in the lobby near the front desk."},
    {"id":"concise-svc-early-10","level":"early","profession":"service","title":"The group-chat sprawl","scenario":"You're telling the staff group chat that tomorrow's delivery moved to 6:30am. Your draft: 'Hey everyone, hope you're all having a good evening! Just a heads up for anyone working tomorrow, I got a call earlier and apparently the delivery that was supposed to come at 8 is now actually coming at 6:30, so whoever is opening should probably know that!' ","task":"Cut it to one line that the opener can't miss.","tips":["Address the person it affects: '@openers' beats 'anyone working tomorrow.'","'I got a call earlier and apparently' is backstory — the new time is the message.","In group chats, short messages get read; paragraphs get 'seen'."],"focus":["concision","impact"],"placeholder":"@openers: tomorrow's delivery moved to 6:30am (was 8)."},
    {"id":"concise-svc-early-11","level":"early","profession":"service","title":"The caveat avalanche","scenario":"A customer asks when the repaired watch will be back. The honest answer is 'Friday, probably.' Your version: 'Well, it should be Friday, but it depends on the courier, and sometimes the workshop gets backed up, and obviously I can't fully promise anything, but in theory, Friday.' Five caveats, one fact.","task":"Give the answer with the fact first and one honest caveat, in one sentence.","tips":["Pick your single strongest caveat; the rest are anxiety, not information.","'Should be Friday — I'll call you if the courier slips' covers everything.","Five hedges make you sound unsure of a thing you're actually sure about."],"focus":["concision","precision"],"placeholder":"Friday — and I'll call you if the courier slips."},
    {"id":"concise-svc-early-12","level":"early","profession":"service","title":"De-corporate the customer notice","scenario":"Head office sent a notice for the door: 'In order to facilitate enhanced service delivery, this location will be implementing revised operational hours effective the 1st.' Your manager asked you to 'make it sound human' before printing.","task":"Rewrite the notice in one or two plain lines with the new hours front and center.","tips":["'Implementing revised operational hours' = 'new hours.'","Customers need the actual times — the notice forgot to include them; add 9-6.","Cut 'in order to facilitate' anything, always."],"focus":["concision","audience"],"placeholder":"New hours from the 1st: 9am-6pm, Monday to Saturday."},
    {"id":"concise-svc-early-13","level":"early","profession":"service","title":"The two-minute specials speech","scenario":"Your specials spiel has grown: origin story of the fish, the chef's inspiration, three adjectives per dish. Tables visibly glaze over by dish two, and your other tables are waiting while you perform it.","task":"Cut the specials to two sentences per dish — what it is and the one thing that sells it.","tips":["One vivid detail per dish beats five adjectives.","Name, key ingredient, price — the rest is available on request.","Watch the table, not the script: glazed eyes mean cut more."],"focus":["concision","audience"]},
    {"id":"concise-svc-early-14","level":"early","profession":"service","title":"Each and every redundant pair","scenario":"Your draft note to the team: 'First and foremost, please make sure that each and every display is fully and completely stocked before opening. This is absolutely essential and vitally important.' Every idea appears twice.","task":"Rewrite the note with every redundant pair collapsed to one word.","tips":["'Each and every' → 'every'; 'fully and completely' → nothing ('stocked' is binary).","'Absolutely essential and vitally important' → 'essential' — or show why instead.","Doubled words don't double the meaning; they halve the attention."],"focus":["concision","clarity"],"placeholder":"Stock every display before opening."},
    {"id":"concise-svc-early-15","level":"early","profession":"service","title":"Gratitude with a payload","scenario":"A coworker covered your shift last week, and now you need her to do it once more, this Thursday. Your draft is five sentences of thanks with the new ask hidden in the last one — and it reads like the thanks were only ever a setup.","task":"Cut it to two sentences: real thanks, clear ask.","tips":["One genuine specific thank-you, then the ask — closeness comes from honesty, not volume.","Don't launder the ask through gratitude; ask plainly.","If she says no, the thanks should still stand on its own."],"focus":["concision","clarity"]},
    {"id":"concise-svc-early-16","level":"early","profession":"service","title":"The late text with a plot","scenario":"You're running 15 minutes late. Your draft text narrates the alarm, the traffic, the missed light. Your manager needs one number and will read the rest never.","task":"Cut the text to under twelve words.","tips":["New arrival time, three-word reason, done.","The story makes it about you; the time makes it about the shift.","Send it the moment you know — brevity buys you speed too."],"focus":["concision","clarity"],"placeholder":"In at 9:15 — traffic. Sorry."},
    {"id":"concise-svc-early-17","level":"early","profession":"service","title":"The care log that buries the facts","scenario":"Your care-visit log entry reads like a diary: 'We had a really lovely morning, chatted about her grandson's wedding, she seemed in much better spirits than Tuesday which was nice to see, and she managed most of her lunch which I was really pleased about.' The next carer needs facts, fast.","task":"Rewrite as 2-3 tight factual lines the next carer can scan.","tips":["Facts a stranger can use: ate most of lunch, mood brighter than Tuesday, no concerns.","Cut your reactions ('I was pleased') — log her state, not yours.","Warmth belongs in the visit; the log is a handover tool."],"focus":["concision","precision"],"placeholder":"Ate most of lunch. Mood noticeably brighter than Tuesday."},
    {"id":"concise-svc-early-18","level":"early","profession":"service","title":"Three softeners deep","scenario":"You need ten minutes of cover for a call from your kid's school. Your draft: 'I hate to ask, and I know it's not ideal timing, and I totally understand if you can't, but is there any way you could maybe watch my section for like ten minutes?' The ask is drowning.","task":"Rewrite in one sentence with at most one softener.","tips":["Pick zero or one softener — 'I know it's busy' — and cut the rest.","State the reason in three words; it earns the ask more than apologies do.","Over-softening makes small asks feel big."],"focus":["concision","clarity"],"placeholder":"Can you watch my section for ten minutes? School's calling about my son."},
    {"id":"concise-svc-early-19","level":"early","profession":"service","title":"Halve the holiday request","scenario":"Your written time-off request is 130 words: your sister's graduation, flight prices, how long since your last holiday, two apologies, and — somewhere — the dates. The form has a three-line box for a reason.","task":"Cut the request to under 40 words without losing the dates or the plan for cover.","tips":["Dates, reason in five words, cover plan — that's the whole genre.","Justifying hard makes it read like you expect a no.","Halve it, then halve it again; you'll be surprised what wasn't needed."],"focus":["concision","structure"]},
    {"id":"concise-svc-early-20","level":"early","profession":"service","title":"The security log, minus the opinions","scenario":"Your patrol log reads: 'Around 11ish I think, saw a guy who looked pretty dodgy hanging around near the car park, he seemed like he was probably up to no good, kept an eye on him for a bit and he eventually cleared off.' Vague times, opinions as facts, filler throughout.","task":"Rewrite as one or two log lines: exact time, observed behavior, action, outcome.","tips":["'Looked dodgy' is opinion; 'circled the car park twice, tried two door handles' is observation.","Times exact: 23:05, not 'around 11ish I think.'","Logs get read in court, worst case — write every line for that reader."],"focus":["concision","precision"],"placeholder":"23:05 — male in dark hoodie circled staff car park twice and tried one door handle."},
    {"id":"concise-svc-early-21","level":"early","profession":"service","title":"The machine's-broken monologue","scenario":"Every customer who tries the coffee machine gets your full explanation: when it broke, what the engineer said, the part on order, the saga of the replacement. There's a queue forming behind each retelling.","task":"Write the one-sentence version you'll say every time, plus an optional second sentence for the truly curious.","tips":["Customers need: it's off, and their nearest alternative.","'Part's on order — hopefully Thursday' covers the curious in five words.","You'll say this fifty times today; every word you cut, you cut fifty times."],"focus":["concision","audience"],"placeholder":"The machine's out of action today — the café next door has great coffee."},
    {"id":"concise-svc-early-22","level":"early","profession":"service","title":"The closing announcement","scenario":"The over-the-speaker closing announcement you inherited runs 45 seconds: 'may we take this opportunity… we do hope you have enjoyed… please kindly make your way in due course…' Shoppers tune it out by second ten.","task":"Rewrite the announcement in two short sentences that people will actually process.","tips":["What they need: closing in 15 minutes, tills at the front.","Warmth fits in a short close: 'thanks for coming — see you tomorrow.'","Airline-speak ('may we take this opportunity') is where attention goes to die."],"focus":["concision","audience"]},
    {"id":"concise-svc-early-23","level":"early","profession":"service","title":"'Can you stay late?' — the direct reply","scenario":"Your manager asks if you can stay two extra hours tonight. You can't — you have your daughter's recital. Your instinct is a two-paragraph apology-explanation. The floor is busy and she needs to ask the next person in the next thirty seconds.","task":"Give a one-sentence spoken answer: the no, the five-word reason, and an offer if you have one.","tips":["A fast clear no helps her more than a slow guilty maybe.","Five-word reason, no documentation: 'my daughter's recital tonight.'","If you can offer something (tomorrow instead), one clause covers it."],"focus":["concision","clarity"],"placeholder":"I can't tonight — my daughter's recital — but I could stay late tomorrow."},
    {"id":"concise-svc-early-24","level":"early","profession":"service","title":"The tip-jar discrepancy, minus the wind-up","scenario":"The card-tip payout on your slip doesn't match the tracker — you're $32 short this cycle. Your draft to the manager spends four sentences establishing that you're not accusing anyone of anything before naming the numbers. The wind-up makes it sound bigger and worse.","task":"Cut the message to two sentences: the discrepancy with numbers, and the ask to check it.","tips":["Numbers first: tracker says $118, slip says $86.","'I'm not accusing anyone' plants the exact idea it denies — cut it.","A calm factual query is self-evidently not an accusation."],"focus":["concision","precision"],"placeholder":"My card tips this cycle came through as $86 but the tracker shows $118 —"},
    {"id":"concise-svc-early-25","level":"early","profession":"service","title":"Training instructions, de-bloated","scenario":"Your written steps for the new hire on making the house latte run 200 words, with warnings, side-notes, and 'the reason we do it this way is…' after every step. He's reading it mid-rush with milk in one hand.","task":"Cut the instructions to five lines, one action each, readable at arm's length.","tips":["Verbs first, numbers in: 'Steam milk to 60°C' not 'you'll want to make sure the milk gets to around the right temperature.'","Move all the whys to a separate 'why' chat later — the card is for hands.","If a line has a comma and an 'also', it's two lines."],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-svc-early-01","level":"early","profession":"service","title":"'Loads of complaints' — count them","scenario":"You tell your manager customers have been complaining 'a lot' about the self-checkout. She can't take 'a lot' to the regional call — she needs a number, a timeframe, and what they actually said.","task":"Rewrite the report with a count, a window, and the top complaint.","tips":["Replace 'a lot' with the tally: how many, over how many days.","Name the most common complaint in the customers' own words.","A number turns a moan into a case."],"focus":["precision","impact"],"placeholder":"Nine customers this week have complained about the self-checkout — seven about the scale error."},
    {"id":"precision-svc-early-02","level":"early","profession":"service","title":"The 'running warm' fridge","scenario":"Your note says the milk fridge 'feels a bit warm.' The manager reading it can't tell if that means 'watch it' or 'move the stock now' — and for a fridge, those are different mornings entirely.","task":"Rewrite the note with the actual reading, the safe limit, and when you measured.","tips":["A thermometer beats an adjective: 9°C at 2pm, limit is 5°C.","Say the trend if you know it: it was 6°C at noon.","The gap between the reading and the limit IS the urgency."],"focus":["precision","clarity"],"placeholder":"Milk fridge read 9°C at 2pm — limit is 5°C, and it was 6°C at noon."},
    {"id":"precision-svc-early-03","level":"early","profession":"service","title":"'Acting suspicious' won't hold up","scenario":"Your security log entry says a man was 'acting suspicious near the tills.' If anything comes of tonight, that line is useless — it records your feeling, not what he did.","task":"Rewrite the entry as observed behavior only: what he did, where, for how long.","tips":["'Suspicious' is a verdict — log the actions that made you think it.","Countable beats vague: circled the till area three times in ten minutes.","Describe clothing and direction of travel, not character."],"focus":["precision","clarity"],"placeholder":"22:10 — male, red jacket, circled the till area three times in ten minutes, watching the counter, bought nothing."},
    {"id":"precision-svc-early-04","level":"early","profession":"service","title":"'She's not eating well' — show the plates","scenario":"You're a carer and you tell the coordinator your client 'hasn't been eating well lately.' That could mean skipped snacks or serious decline — and what the coordinator does next depends entirely on which.","task":"Rewrite the concern with specifics: which meals, how much, over how many days.","tips":["Count what you saw: half of lunch Monday, a few bites Wednesday, refused Thursday.","Compare to her normal — the change is the evidence.","Vague concern gets a note in the file; specific concern gets a response."],"focus":["precision","audience"],"placeholder":"Over the last four visits she's eaten less than half her lunch each time — a month ago she finished it daily."},
    {"id":"precision-svc-early-05","level":"early","profession":"service","title":"'We're always slammed on weekends'","scenario":"You want another server on Saturday nights and your pitch is 'weekends are always crazy.' Your manager hears that from everyone about every shift. What she hasn't seen is the number that proves this one.","task":"Rewrite the case with counts: covers, servers, and what it costs.","tips":["Ratio is the story: 60 covers across two servers, versus 40 across three on Fridays.","Add the cost: four walkouts before 8pm last Saturday.","'Always' invites debate; 'the last three Saturdays' doesn't."],"focus":["precision","impact"],"placeholder":"The last three Saturdays we ran 60+ covers with two servers — and lost four tables to the wait before 8pm."},
    {"id":"precision-svc-early-06","level":"early","profession":"service","title":"'The new till is way faster' — prove it","scenario":"You told the owner the new till system is 'way faster' and she raised an eyebrow: it cost real money, and 'way faster' is what the salesman said too. You've actually used both for a week each.","task":"Rewrite the claim with a measured comparison a skeptic would accept.","tips":["Time the same transaction on both: a five-item sale, card payment.","Give both numbers, not just the good one.","One honest measurement beats three enthusiastic adjectives."],"focus":["precision","impact"],"placeholder":"A five-item card sale takes about 25 seconds on the new till — it was 45 on the old one."},
    {"id":"precision-svc-early-07","level":"early","profession":"service","title":"The 'soon' that helps nobody","scenario":"A customer asks when the winter boots come back in stock and you hear yourself say 'soon, hopefully.' She drove twenty minutes for these. 'Soon' means she either wastes another trip or gives up and buys elsewhere.","task":"Give a 1-2 sentence answer with a real day and your confidence in it.","tips":["Look it up if you can — 'Thursday's delivery' beats any guess.","Mark your confidence honestly: confirmed, or expected.","Offer the safety net: take her number, call when they land."],"focus":["precision","audience"],"placeholder":"They're on Thursday's delivery — that's confirmed. Want me to take your number and call when they're on the shelf?"},
    {"id":"precision-svc-early-08","level":"early","profession":"service","title":"'The room is really bad' — itemize it","scenario":"You're housekeeping and room 318's checkout left it in a state that needs more than the standard 25 minutes. Telling your supervisor it's 'really bad in there' gets you sympathy, not the extra time or the deep-clean charge.","task":"Write a 2-3 sentence report itemizing what's wrong and the time you need.","tips":["Name the specifics: carpet stain the size of a dinner plate, broken glass, smoke smell.","Convert to the ask: 90 minutes and the ozone machine.","An itemized list also backs up the guest charge — write it like evidence."],"focus":["precision","concision"],"placeholder":"318 needs a deep clean, not a standard turn: red-wine stain on the carpet, broken glass by the bed, heavy smoke smell."},
    {"id":"precision-svc-early-09","level":"early","profession":"service","title":"The pastry waste, counted","scenario":"You're sure the café over-orders croissants — you bin unsold ones most nights. You've said 'we throw loads away' twice and nothing changed. This week you actually counted: 11, 9, and 14 binned across three days, against 30 ordered daily.","task":"Write a 2-3 sentence note that turns your counts into one clear conclusion and an ask.","tips":["Lead with the pattern the numbers show: roughly a third goes in the bin.","Show your working in one line: 34 binned across three days, 90 ordered.","End with the specific change: drop the daily order to 22 and review Friday."],"focus":["precision","structure"],"placeholder":"We're binning about a third of the croissants — 34 of 90 across the last three days."},
    {"id":"precision-svc-early-10","level":"early","profession":"service","title":"'Fridays feel slow' — time the turns","scenario":"Friday tables feel like they sit forever between courses, and you suspect the kitchen batching is why. 'Fridays feel slow' will start an argument with the kitchen; a timed number will start a conversation.","task":"Describe in 2 sentences what you'd measure this Friday and how you'd report it.","tips":["Pick one measurable: minutes from mains ordered to mains served, five tables.","Compare like with like: same measure on a Tuesday.","Bring the numbers, not the blame — let the gap speak."],"focus":["precision","structure"],"placeholder":"This Friday I'll time five tables from mains ordered to served, then the same on Tuesday —"},
    {"id":"precision-svc-early-11","level":"early","profession":"service","title":"What, so what, now what","scenario":"You noticed six people leave the coffee queue without ordering during this morning's rush. Reporting just the fact leaves your manager saying 'huh.' A complete point says what you saw, why it matters, and what to do about it.","task":"Write a 3-sentence update: the observation, what it costs, and your suggested fix.","tips":["What: six walkaways between 8 and 8:40.","So what: that's roughly $30 of orders and they'll try the place across the road.","Now what: propose the fix — a second person on the machine till 9."],"focus":["precision","impact"],"placeholder":"Six people left the queue without ordering between 8 and 8:40 this morning. That's about $30 walked out the door —"},
    {"id":"precision-svc-early-12","level":"early","profession":"service","title":"'Around midnight, some kids'","scenario":"Your patrol log reads: 'Around midnight some kids were messing about by the west fence, moved them on.' Three weeks from now, if that fence turns up cut, this entry answers none of the questions anyone will ask.","task":"Rewrite the entry with exact time, count, description, location, and action taken.","tips":["Time from your phone, not your memory: 23:52, not 'around midnight.'","Count and describe: three teenagers, one with a red BMX.","Record their direction when they left — that's the detail future-you always wants."],"focus":["precision","structure"],"placeholder":"23:52 — three teenagers at the west fence near gate 4, one with a red BMX; moved on without issue, left south toward the car park."},
    {"id":"precision-svc-early-13","level":"early","profession":"service","title":"The vacuum case, in minutes","scenario":"You've told your cleaning supervisor twice that the vacuum 'takes forever now.' This week you timed it: floor two took 55 minutes against your usual 35. That's the number that gets a replacement approved — if you use it.","task":"Write a 2-sentence note built on the timed comparison.","tips":["Both numbers, side by side: 55 minutes now, 35 before.","Multiply it out: 20 extra minutes × 4 floors = over an hour a night.","The multiplication is what turns an annoyance into a cost."],"focus":["precision","impact"],"placeholder":"The vacuum is adding 20 minutes per floor — 55 minutes on floor two this week versus my usual 35."},
    {"id":"precision-svc-early-14","level":"early","profession":"service","title":"The skeptic's 'says who?'","scenario":"You want to tell the owner the specials board is working. The owner's default reply to every claim is 'says who, by how much?' Your draft says specials are 'selling really well' — which will not survive contact.","task":"Rewrite the claim so it survives the skeptic: numbers, comparison, timeframe.","tips":["Anticipate 'how do you know' and answer it in the sentence.","Compare to something: specials are 20% of dinner sales, up from almost none.","If you don't have the number, get it before the conversation — not during."],"focus":["precision","impact"],"placeholder":"The specials board is earning its spot: 31 specials sold this week, about 20% of dinner mains."},
    {"id":"precision-svc-early-15","level":"early","profession":"service","title":"'She seemed off today'","scenario":"You're a carer writing the visit log, and your instinct is to write 'Mrs. K seemed a bit off today.' The next carer — and her GP, if it comes to that — need observables: what you saw, when, compared to what.","task":"Rewrite the entry as 2-3 lines of observable fact.","tips":["Log what 'off' actually looked like: slower answers, left her tea, stayed in the chair all visit.","Anchor to her baseline: normally she's up and chatting by 10.","Your unease is a signal — the observations are what make it usable."],"focus":["precision","audience"],"placeholder":"10am visit: answered slowly, left her tea untouched, stayed in the armchair throughout — normally she's up and chatting."},
    {"id":"precision-svc-early-16","level":"early","profession":"service","title":"The out-of-date sweep","scenario":"You found expired stock on the shelves and your first draft to the manager says 'loads of stuff out of date in the fridge aisle.' You actually checked: 14 items, three products, all from the same delivery week.","task":"Write a 2-sentence report with the count, the cluster, and what it points to.","tips":["The cluster is the insight: all three products came in the same week.","Count and name: 14 items across yogurts, dips, and juice.","'Loads of stuff' gets a shrug; 'one delivery week' gets a process fix."],"focus":["precision","structure"],"placeholder":"I pulled 14 out-of-date items this morning — three products, all from the March 4th delivery."},
    {"id":"precision-svc-early-17","level":"early","profession":"service","title":"Forty returns, one insight","scenario":"The manager asked you to look at last month's returns before the team meeting. The printout has forty rows. She doesn't want forty rows read aloud — she wants the one thing the pile reveals: 19 of them are the same kettle, all for the same fault.","task":"Write the 2-sentence summary that states the insight, with the numbers as support.","tips":["Lead with the pattern, not the pile: half our returns are one product.","Keep two numbers, drop the other thirty-eight.","Data plus meaning is a finding; data alone is homework you're handing her."],"focus":["precision","concision"],"placeholder":"Half of last month's returns are one product: 19 of 40 were the same kettle, all for the lid catch."},
    {"id":"precision-svc-early-18","level":"early","profession":"service","title":"Twelve comment cards, one sentence","scenario":"The hotel's morning brief gives you thirty seconds to summarize the week's guest comment cards. There are twelve: four praise the breakfast staff by name, five complain about slow check-in on Friday, three are one-offs.","task":"Give the one-sentence headline you'd say, then one supporting line.","tips":["Cluster first: the five Friday check-in complaints are the story.","Keep one bright spot — named praise is worth repeating aloud.","One-offs get filed, not aired."],"focus":["precision","concision"],"placeholder":"The week's pattern is Friday check-in: five of twelve cards flagged the queue between 4 and 6pm."},
    {"id":"precision-svc-early-19","level":"early","profession":"service","title":"'The heating's been weird'","scenario":"You clean an office building at night and the third floor has been either freezing or stifling for a week. Your report — 'heating's been weird on 3' — went nowhere. Facilities responds to readings, times, and locations.","task":"Rewrite the report with specifics facilities can act on.","tips":["When and where, exactly: 3rd floor east side, after 9pm, all five nights this week.","Describe the pattern: radiators scalding while the thermostat reads 17.","One specific symptom out-argues a week of 'weird.'"],"focus":["precision","clarity"],"placeholder":"3rd floor east has run hot after 9pm all five nights this week — radiators scalding while the wall thermostat reads 17."},
    {"id":"precision-svc-early-20","level":"early","profession":"service","title":"The honest wait time","scenario":"There's a forty-minute wait for tables and the couple at the front asks how long. The kind-feeling answer is 'shouldn't be too long.' The kind answer is the real number — they can't make a good decision with a soft one.","task":"Give a 1-2 sentence answer with a real number and an honest range.","tips":["Say the number you believe, not the number they want: 35 to 45 minutes.","Give them something to do with it: the bar, or a callback when it's close.","Under-promising by a little beats over-promising by anything."],"focus":["precision","audience"],"placeholder":"Honestly, 35 to 45 minutes right now. I can take your number and text you when you're next up —"},
    {"id":"precision-svc-early-21","level":"early","profession":"service","title":"'The meal deal is doing great'","scenario":"Head office asked each café how the new meal deal is landing. Your manager drafted 'it's been really popular with our customers!' — which reads as 'we didn't check.' The till data is right there: 210 sold in week one.","task":"Rewrite the reply with the figure and one comparison that gives it meaning.","tips":["A number without a comparison floats: 210 sold — against what?","Anchor it: that's roughly one in five lunchtime transactions.","'Popular' is a feeling; 'one in five' is a fact head office can use."],"focus":["precision","impact"],"placeholder":"We sold 210 meal deals in week one — roughly one in five lunchtime transactions."},
    {"id":"precision-svc-early-22","level":"early","profession":"service","title":"The supplies order that guesses","scenario":"Your text to the cleaning supervisor says 'we're nearly out of basically everything.' She orders from that — which is how you ended up with six boxes of gloves and no descaler last month.","task":"Rewrite as an itemized request with counts and sizes.","tips":["Item, size, quantity left, quantity needed — one line each.","Flag the true zeros: OUT beats 'nearly out.'","The five minutes you spend counting saves a week of improvising."],"focus":["precision","structure"],"placeholder":"OUT: descaler, blue roll. LOW: gloves medium (1 box left, need 4), glass cleaner (2 bottles, need 6)."},
    {"id":"precision-svc-early-23","level":"early","profession":"service","title":"The damage list for the insurer","scenario":"Someone forced the storeroom window overnight and your manager needs a damage report for the insurance claim by noon. 'The window's smashed and some stock got wrecked' will bounce back with questions; the claim needs an inventory.","task":"Write the report as a precise list: what's damaged, how badly, roughly what it's worth.","tips":["One line per item: window frame bent and glass gone; two cases of spirits smashed.","Estimate values where you can and mark them as estimates.","Photos referenced by item ('photo 3') make the list twice as strong."],"focus":["precision","structure"],"placeholder":"Storeroom window: frame bent, glass smashed (photos 1-2). Stock: two cases of spirits broken, approx. $340 (photo 3)."},
    {"id":"precision-svc-early-24","level":"early","profession":"service","title":"'People keep tripping there'","scenario":"Customers keep catching their toe on the curled mat edge by the entrance, and your 'people keep tripping there' has been noted twice and fixed never. This week you kept a tally: five stumbles in two days, one involving a woman with a cane.","task":"Write a 2-3 sentence report using the tally to force a decision.","tips":["Counted incidents in a timeframe: five in two days.","Include the one detail that raises the stakes: a customer with a cane.","End with the immediate ask: tape it down today, replace it this week."],"focus":["precision","impact"],"placeholder":"The entrance mat caused five stumbles in the last two days — one was a customer with a cane."},
    {"id":"precision-svc-early-25","level":"early","profession":"service","title":"'Never enough towels' — count a week","scenario":"Housekeeping group chat wisdom says the third floor 'never has enough towels.' You ran the numbers for a week: the floor starts with 40, needs about 55 on full occupancy, and runs dry by 2pm four days out of five.","task":"Write a 2-sentence case to the head housekeeper built on the week of counts.","tips":["The gap is the message: stocked 40, needs 55.","Frequency proves it's structural: dry by 2pm four days of five.","Ask for the specific fix: raise the par level to 60."],"focus":["precision","impact"],"placeholder":"Floor 3 runs out of towels by 2pm four days out of five — we stock 40 but full occupancy uses about 55."}
  ],
  "executive-presence": [
    {"id":"presence-svc-early-01","level":"early","profession":"service","title":"'Whichever you think' — own the pick","scenario":"Your manager asks whether the sale display should go by the door or by the tills. You spent all week watching customers walk past both spots — and you answer 'whichever you think is best.' You just handed back the one decision you were best placed to make.","task":"Rewrite your answer to own a clear recommendation with your reason.","tips":["State your pick in the first sentence, then the reason.","Mention the other option and why you'd pass: door traffic doesn't stop, till queue does.","A recommendation shows you were watching; a shrug says you weren't."],"focus":["impact","clarity"],"placeholder":"By the tills. People stand in that queue for two minutes with nothing to do — the door crowd never stops walking."},
    {"id":"presence-svc-early-02","level":"early","profession":"service","title":"'This is probably silly, but…'","scenario":"You've figured out a fix for the morning bottleneck at the coffee machine, and you open your pitch to the manager with 'this is probably a silly idea, but…' You've told her to discount it before she's heard it.","task":"Rewrite the opening so the idea arrives with quiet confidence.","tips":["Delete the pre-apology entirely — it buys you nothing.","Open with what the idea fixes: the 8am queue.","You can be open to feedback without inviting dismissal."],"focus":["impact","clarity"],"placeholder":"I've got a fix for the 8am bottleneck that's worth trying —"},
    {"id":"presence-svc-early-03","level":"early","profession":"service","title":"Signpost the huddle update","scenario":"It's your turn to speak at the pre-shift huddle and you have three things: a menu change, a large booking at 7, and a card-machine workaround. Launching straight in means people can't tell what's coming or when you'll finish.","task":"Script the opening line that maps your three points, then deliver the first.","tips":["'Three things, thirty seconds' — the map buys you the room's attention.","Take them in order of what matters most tonight.","Signposting reads as command of your material, because it is."],"focus":["structure","impact"],"placeholder":"Three quick things: the fish is off tonight, we've a 12-top at 7, and there's a card-machine workaround."},
    {"id":"presence-svc-early-04","level":"early","profession":"service","title":"'I guess I could maybe ask someone?'","scenario":"A customer's online order has vanished from the system and she's getting agitated. Your honest answer came out as 'um, I guess I could maybe ask someone about it?' — which told her nobody is in charge, least of all you.","task":"Rewrite as 1-2 sentences that take visible ownership of the next step.","tips":["'Here's what I'm going to do' is the phrase — then do it.","Give her a timeline: two minutes while I check with the desk.","You don't need the answer to have command — you need the next step."],"focus":["audience","impact"],"placeholder":"Here's what I'll do: I'm going to check this with our collections desk right now — give me two minutes."},
    {"id":"presence-svc-early-05","level":"early","profession":"service","title":"Fact and opinion, untangled","scenario":"Your report on the delivery driver reads: 'He was late AGAIN and honestly he's completely useless and doesn't care.' Your manager needs the facts separated from your read — blended together, both look weaker.","task":"Rewrite as two labeled parts: the observable facts, then your assessment.","tips":["Facts first, plainly: late three of the last four Tuesdays, 40+ minutes each.","Then your read, marked as a read: 'my take — this route is failing.'","Separating them is what makes people trust both."],"focus":["precision","impact"],"placeholder":"The facts: he's been 40+ minutes late three of the last four Tuesdays. My read: this route isn't working —"},
    {"id":"presence-svc-early-06","level":"early","profession":"service","title":"'Definitely' versus 'should'","scenario":"Yesterday you told a guest her dry cleaning would 'definitely' be back by 6 — it wasn't, and today's conversation is worse for it. The courier had said 'probably.' Your words claimed more certainty than you had.","task":"Rewrite yesterday's promise with honest calibration, and today's follow-up.","tips":["Match your words to your actual confidence: 'expected by 6, I'll confirm at 4.'","Calibrated language isn't weak — it's what lets people plan.","Today: own the miss in one sentence, then the new, honest time."],"focus":["precision","audience"],"placeholder":"It's expected back by 6 — I'll check with the courier at 4 and confirm either way."},
    {"id":"presence-svc-early-07","level":"early","profession":"service","title":"The fire alarm voice","scenario":"The fire alarm just went off mid-service and it's not a drill notice you've seen. Thirty diners are looking around. What you say in the next ten seconds sets whether this is an orderly walk or a scramble.","task":"Script the 2-sentence announcement you'd deliver, calm and unmistakable.","tips":["Short declaratives: what's happening, what to do, where to go.","Strip every hedge — 'I think we should probably' has no place in an alarm.","A steady voice instructs; volume alone alarms."],"focus":["clarity","impact"],"placeholder":"Everyone, we need to step outside — please leave your things and walk to the main doors now. Staff will guide you to the car park."},
    {"id":"presence-svc-early-08","level":"early","profession":"service","title":"Owning the pricing mistake","scenario":"You just realized you've been ringing the discount wrong for two hours — about fifteen customers undercharged. Panic-confessing in a heap ('I'm so sorry, I'm such an idiot') makes your manager manage YOU instead of the problem.","task":"Write the 2-3 sentence report: what happened, the size of it, and your proposed next step.","tips":["State it like a professional reporting an error, not a child confessing.","Quantify: roughly 15 transactions, about $4 each.","Bring the next step with the news: I've corrected the code; here's the till report."],"focus":["impact","structure"],"placeholder":"I've been applying the discount wrong since 10 — about 15 transactions, roughly $4 each. It's fixed now, and I've printed the till report."},
    {"id":"presence-svc-early-09","level":"early","profession":"service","title":"Steady in front of the trainee","scenario":"A customer is loudly demanding a refund you can't give, and your first-week trainee is standing beside you, watching how this goes. Whatever you model in the next minute is what she'll do for the next year.","task":"Script your first two sentences to the customer — calm, firm, and worth copying.","tips":["Lower your pace, not your standards: slow words read as control.","Acknowledge once, then state what you CAN do.","You're speaking to two audiences; the calm is for both."],"focus":["audience","impact"],"placeholder":"I hear you — this is frustrating. Here's what I can do right now: exchange it or issue a gift card at today's price."},
    {"id":"presence-svc-early-10","level":"early","profession":"service","title":"'Whatever you all think' at the vote","scenario":"The manager asks the team point-blank whether the café should move last orders from 5:30 to 5:00 — and asks you first, since you close most days. You know exactly what you think. 'Whatever everyone else thinks' is on its way out of your mouth.","task":"Give a 2-sentence spoken answer that states your view and your best reason.","tips":["You closed those shifts — you've earned a view. State it.","One reason, your strongest: nobody orders food after 5:10 anyway.","You can hold a view and stay open: 'that's my experience — keen to hear the openers.'"],"focus":["impact","concision"],"placeholder":"Move it to 5:00. In three months of closes I can count the post-5:10 orders on one hand."},
    {"id":"presence-svc-early-11","level":"early","profession":"service","title":"'Mistakes were made' — by whom?","scenario":"Your incident note says 'the booking got double-entered and the table ended up being given away.' Every verb is hiding. You double-entered it; the head waiter gave the table away. Passive voice reads like dodging even when it isn't.","task":"Rewrite the note with owners on every action, including yours.","tips":["Name the actor: 'I entered the booking twice.'","Owning your part first makes the rest of the report credible.","Active voice isn't about blame — it's about a report someone can act on."],"focus":["clarity","precision"],"placeholder":"I entered the Chen booking twice on Tuesday. When the duplicate looked like a no-show, Marco released the table —"},
    {"id":"presence-svc-early-12","level":"early","profession":"service","title":"The area manager asks 'how's it going?'","scenario":"The area manager is on a surprise visit, turns to you by the stockroom, and asks 'so how are things running here?' You'll either mumble 'yeah, good' or say something worth her ten seconds. You know this store's real state: strong team, weak delivery slots.","task":"Give a composed 2-3 sentence answer with one genuine positive and one honest issue.","tips":["Have a shape: going well overall, one thing worth knowing.","Pick a real positive, not flattery — the new rota works.","Raising one honest issue reads as ownership, not complaint — if you attach what would fix it."],"focus":["structure","audience"],"placeholder":"Running well — the new rota's made a real difference. The one thing worth knowing: our delivery slot moved to mid-rush, and it costs us the floor every Tuesday."},
    {"id":"presence-svc-early-13","level":"early","profession":"service","title":"Newest on the team, still worth hearing","scenario":"You're three weeks in, and at the huddle you can see the queue problem everyone's describing has a simple fix: move the pickup shelf. Your draft opener is 'I know I'm new here, so this might be off, but…' — three apologies before one idea.","task":"Script the 2-sentence version that offers the idea straight.","tips":["'I'm new' is visible; announcing it just discounts you.","Fresh eyes are your credential — what you've noticed IS the contribution.","Offer it as an observation plus suggestion, no permission slip needed."],"focus":["impact","concision"],"placeholder":"I've noticed the queue and the pickup crowd collide at the same corner. Could we move the pickup shelf to the far end?"},
    {"id":"presence-svc-early-14","level":"early","profession":"service","title":"Talked over at the huddle","scenario":"You were halfway through flagging the broken door sensor when a louder coworker rolled over you and the huddle moved on. The sensor still matters — someone will get a door in the face. You have one beat to re-enter without either shrinking or snapping.","task":"Script the one calm sentence you'd use to bring the point back.","tips":["Re-enter with the point, not the grievance: 'before we break — the door sensor.'","Steady and brief beats loud; the room notices composure.","If it can't land now, name the follow-up: 'I'll grab you after, it's a safety one.'"],"focus":["impact","clarity"],"placeholder":"Before we break — the front door sensor is still down, and it's a safety one."},
    {"id":"presence-svc-early-15","level":"early","profession":"service","title":"The fire lane, cleared politely","scenario":"You're on security and a driver has parked square across the fire lane, flashers on, 'just two minutes.' You need him moved now — without a standoff in front of thirty shoppers.","task":"Script the 1-2 sentence instruction: firm, courteous, no wiggle room.","tips":["Polite words, non-negotiable content: 'I need you to move it now.'","Give the reason in five words — it's the fire lane.","Offer the alternative in the same breath: loading bay is twenty meters on."],"focus":["audience","impact"],"placeholder":"Morning — I need this moved right away, it's the fire lane. The loading bay is just past the pillar, twenty meters on."},
    {"id":"presence-svc-early-16","level":"early","profession":"service","title":"Second-guessed by the family","scenario":"You're a carer, and your client's son — visiting for the first time in months — is questioning the lunch routine you've run successfully for a year. Getting defensive loses the room; folding instantly loses the routine that works.","task":"Give a 2-3 sentence response that stays steady: acknowledge, explain the reason, stay open.","tips":["Take the concern seriously without taking it personally.","Give the reason the routine exists: she eats best before her 1pm medication.","Invite the check that settles it: the care plan and the coordinator's number."],"focus":["audience","clarity"],"placeholder":"That's a fair question. We settled on 12:15 because she eats best before her 1pm tablets — it's in the care plan, and I'm happy to give you the coordinator's number."},
    {"id":"presence-svc-early-17","level":"early","profession":"service","title":"Delivering a policy you didn't choose","scenario":"Head office banned personal bags behind the bar, effective today, and half the team hates it. You're telling your shift. 'Don't blame me, head office says…' undermines the policy AND you — but pretending you invented it is worse.","task":"Script 2-3 sentences that deliver the change with ownership but without spin.","tips":["State the change and the start date plainly — no eye-rolling preamble.","Give the reason it exists in one straight line.","Own the enforcement even if you didn't own the decision: 'on my shifts, this is how we run.'"],"focus":["audience","impact"],"placeholder":"From today, personal bags go in the lockers, not behind the bar. It's about till-area security, and on my shifts it's how we run."},
    {"id":"presence-svc-early-18","level":"early","profession":"service","title":"'I'll try' is not a commitment","scenario":"A guest asks if her room can be ready early tomorrow, and your reflex is 'I'll try my best!' — which she'll hear as yes and you meant as maybe. Presence is saying exactly what you're committing to.","task":"Rewrite the reply so it commits to something real and marks the rest honestly.","tips":["Commit to the action you control: I'll flag it as the first room serviced.","Mark the part you don't: I can't guarantee before noon.","A precise 'here's what I'll do' beats a warm 'I'll try' every time."],"focus":["precision","audience"],"placeholder":"Here's what I can do: I'll flag your room to be serviced first, which usually means ready by 11 — I can't promise it, but I'll text you the moment it is."},
    {"id":"presence-svc-early-19","level":"early","profession":"service","title":"The composed flood report","scenario":"The dishwasher line just let go and there's water spreading across the kitchen floor. Your all-caps draft — 'EMERGENCY!!! FLOODING EVERYWHERE COME NOW!!!' — transmits panic, not information. Your manager is off-site and needs to make decisions from your words alone.","task":"Rewrite as 2-3 sentences: situation, what you've done, what you need.","tips":["Urgent and calm can coexist: 'water across half the kitchen floor, spreading slowly.'","Say what's handled: water main off, kitchen closed, wet-floor signs out.","End with the decision you need from her, not a scream for presence."],"focus":["clarity","structure"],"placeholder":"The dishwasher line burst — water across half the kitchen floor, spreading slowly. I've shut the water off and closed the kitchen. Do you want the emergency plumber or can it wait for Tom at 4?"},
    {"id":"presence-svc-early-20","level":"early","profession":"service","title":"Disagreeing with the boss's favorite idea","scenario":"Your manager loves the new 'free coffee with any pastry' promo. You've worked every morning of it: it's queue chaos, and the pastry case sells out by 9 leaving regulars annoyed. She just asked how it's going, visibly expecting good news.","task":"Give a 2-3 sentence answer that's honest, respectful, and specific.","tips":["Don't soften into a lie; don't sharpen into a verdict on her judgment.","Facts do the disagreeing for you: sold out by 9, queue past the door, regulars walking.","Offer the salvage: limit it to 7-9am and it might actually work."],"focus":["audience","impact"],"placeholder":"Mixed, honestly. It's driving real traffic — but the case sells out by 9 and the queue is costing us regulars. Capping it at 7-to-9 might keep the good half."},
    {"id":"presence-svc-early-21","level":"early","profession":"service","title":"The curveball in the team-lead chat","scenario":"You're being considered for shift lead, and the manager tosses you a curveball over coffee: 'What's the first thing you'd change around here?' A blurted answer sounds rash; a long pause followed by rambling sounds worse. A beat of thought, then a shaped answer, wins.","task":"Give a structured 3-sentence answer: your pick, the reason, how you'd start.","tips":["It's fine to take three seconds — 'good question' buys you two of them.","One change, not five: the answer is a window into how you think.","Ground it in something you've seen, not something you've read."],"focus":["structure","impact"],"placeholder":"The handovers. Half the evening problems trace back to things the day shift knew and didn't write down — I'd start with a five-line template on the board."},
    {"id":"presence-svc-early-22","level":"early","profession":"service","title":"The signposted training walk-through","scenario":"You're teaching the new hire the whole closing routine — twenty minutes of material. Without a map she'll be lost by minute three, nodding and retaining nothing. Presence in teaching is structure she can hold onto.","task":"Script your opening 2 sentences: the map of what's coming and where you'll start.","tips":["Name the parts up front: tills, floor, locks — in that order.","Tell her what she'll do versus watch: 'you'll run the till count with me.'","A learner with a map asks questions; one without just nods."],"focus":["structure","audience"],"placeholder":"Closing has three parts — tills, floor, locks — and we'll do them in that order. You'll run the till count yourself with me beside you."},
    {"id":"presence-svc-early-23","level":"early","profession":"service","title":"Radio steady during the incident","scenario":"Two men are squaring up near the venue bar and you need backup on the radio. Panic in your voice will spread to every earpiece on the channel and into the crowd around you. The words and the tone both need to be flat and fast.","task":"Script the one-sentence radio call: location, situation, what you need.","tips":["Format under pressure: where, what, need — ten words if you can.","Flat tone is a skill: rehearse the shape so the shape carries you.","No commentary, no 'oh god' — the channel is for facts."],"focus":["concision","impact"],"placeholder":"Main bar, two males squaring up — need one more body here now."},
    {"id":"presence-svc-early-24","level":"early","profession":"service","title":"The rota recommendation, made properly","scenario":"You think the Sunday rota should move from three short shifts to two long ones — you've worked both patterns. You could float it as a half-formed 'what if maybe…' at the huddle, or make an actual recommendation to your manager.","task":"Write the 3-sentence recommendation: your proposal, the evidence, the acknowledged trade-off.","tips":["Propose, don't muse: 'I recommend two long shifts on Sundays.'","Evidence from experience: handover chaos at 2pm is where Sunday complaints cluster.","Naming the trade-off yourself — longer days for those two people — is what makes it credible."],"focus":["structure","impact"],"placeholder":"I'd move Sundays to two long shifts instead of three short ones. Every Sunday complaint I've seen traces to the 2pm double-handover."},
    {"id":"presence-svc-early-25","level":"early","profession":"service","title":"Firm with a regular, warm as ever","scenario":"A well-liked regular insists his loyalty card entitles him to the discount on top of sale prices — it doesn't, it never has, and he's now performing his disappointment to the queue. You need to hold the line without losing the regular.","task":"Script a 2-sentence response: warm in tone, immovable on the policy.","tips":["Warmth and firmness aren't opposites — deliver the no like you'd deliver his usual order.","Don't relitigate the policy at volume; state it once, simply.","Give him a graceful exit: what the card DOES get him today."],"focus":["audience","precision"],"placeholder":"I wish I could stack them for you, but the card doesn't combine with sale prices — never has, I promise it's not new. It'll still get you the points on today's shop, though."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-svc-early-01","level":"early","profession":"service","title":"'Did the delivery come?' — yes or no first","scenario":"Your manager calls mid-rush: 'Did the linen delivery come?' It did — but short two bags, and the driver said the rest comes tomorrow. Your instinct is to start with the driver story. Her question takes one word to answer.","task":"Give a spoken answer that starts with yes or no, then the one complication.","tips":["Answer the asked question in word one: 'Yes.'","Then the exception: 'short two bags, rest tomorrow.'","Details on request — she'll ask if she needs them."],"focus":["clarity","concision"],"placeholder":"Yes — but short two bags. Driver says the rest lands tomorrow morning."},
    {"id":"pressure-svc-early-02","level":"early","profession":"service","title":"The allergen question you can't answer","scenario":"A customer asks whether the flapjacks contain sesame. You genuinely don't know, and this is exactly the question where a confident guess could hurt someone. 'I don't know' feels like failure — said right, it's the most trustworthy sentence you have.","task":"Script the 2-sentence response: the honest 'I don't know' plus the immediate action.","tips":["Say it cleanly: 'I don't know — and for allergens I won't guess.'","Attach the action in the same breath: checking the label or the kitchen now.","Give a time: 'two minutes' turns uncertainty into service."],"focus":["clarity","audience"],"placeholder":"I don't know, and with allergens I'm not going to guess — give me two minutes to check the packaging with the kitchen."},
    {"id":"pressure-svc-early-03","level":"early","profession":"service","title":"'Why does this ALWAYS happen?'","scenario":"A guest's room key has failed for the second time today and she snaps: 'Why does this always happen at this hotel?' The literal question has no good answer. The real question underneath is: will someone fix this properly, right now?","task":"Give a 2-sentence response that answers the real question, not the rhetorical one.","tips":["Don't defend the hotel's record or debate 'always' — that's the trap.","Answer what she actually needs: a key that works and a reason to believe it.","One acknowledgment, one concrete fix, no essay."],"focus":["audience","impact"],"placeholder":"Twice in one day is genuinely not okay — let me fix it properly this time. I'm re-cutting both keys and testing them in the door with you."},
    {"id":"pressure-svc-early-04","level":"early","profession":"service","title":"'Why was your till short?' — facts, no guessing","scenario":"At the shift-end check your manager asks flat out: 'Why is your till $15 short?' You don't know. Under that stare, the temptation is to speculate — 'maybe the card machine, or that refund, or…' Every guess sounds like a cover story.","task":"Give the answer that states what you know, what you don't, and what you'll do.","tips":["The honest shape: 'I don't know yet — here's what I do know.'","Offer verifiable facts: counted twice, no voids after 6, one cash refund.","Propose the check: walk the till roll together, now."],"focus":["precision","clarity"],"placeholder":"I don't know yet. I counted twice, there were no voids after 6, and one cash refund at 4:30 — can we walk the till roll together?"},
    {"id":"pressure-svc-early-05","level":"early","profession":"service","title":"'Are you refusing to serve me?'","scenario":"You've declined to serve another drink to a customer who's clearly had enough, and he leans in: 'So you're REFUSING to serve me?' It's a loaded question — agreeing to his framing escalates, denying it sounds like backpedaling.","task":"Script a calm 1-2 sentence response that restates what's actually happening.","tips":["Don't adopt his words — state yours: 'I can't serve you more alcohol tonight.'","Give the neutral reason once: it's the law and my job, not a judgment.","Offer what IS available: water, food, a taxi called."],"focus":["audience","precision"],"placeholder":"What's happening is I can't serve you more alcohol tonight — that's the law, not a judgment. I can get you water or food, and I'm happy to call you a taxi."},
    {"id":"pressure-svc-early-06","level":"early","profession":"service","title":"The inspector asks about the gap","scenario":"The health inspector runs a finger down the fridge temperature log and asks: 'Why is Tuesday afternoon blank?' It's blank because the shift was slammed and it got missed. A cover story would be catastrophic; a shrug would be almost as bad.","task":"Give the direct answer: what happened, and what stops it happening again.","tips":["The truth, undecorated: 'It got missed — Tuesday's shift was short-staffed.'","No invented explanations — inspectors are professional lie detectors.","Close with the correction: the new check is tied to the 2pm break rotation."],"focus":["clarity","impact"],"placeholder":"It got missed — we were two people down that afternoon and the 2pm check didn't happen. We've since tied it to the break rotation so it can't slip again."},
    {"id":"pressure-svc-early-07","level":"early","profession":"service","title":"'Can you guarantee a quiet room?'","scenario":"A guest booking for her exam week asks: 'Can you guarantee the room will be quiet?' You can't — there's a wedding party in Saturday. Over-promising creates Sunday's complaint; a flat 'no guarantees' loses the booking.","task":"Give a calibrated 2-sentence answer: what you can promise, what you can't, honestly.","tips":["Split it: what you control (floor, end of corridor) versus what you don't.","Volunteer the wedding — she'll find out anyway, and honesty now beats a review later.","End with the real commitment: quietest room available, and a move if it fails."],"focus":["precision","audience"],"placeholder":"I can put you on the top floor at the end of the corridor, away from the lifts. I'll be straight with you — there's a wedding party Saturday night — but if noise reaches you, call down and I'll move you."},
    {"id":"pressure-svc-early-08","level":"early","profession":"service","title":"Three questions at once, mid-rush","scenario":"Mid-Saturday-rush, your manager fires three questions in one breath: 'Is the 6 o'clock booking confirmed, did the ice arrive, and where's Callum?' You know two answers and not the third. Answering in a tangle wastes the ten seconds you have.","task":"Give the spoken answer that takes each in turn, fast, flagging the unknown.","tips":["Mirror her order: booking, ice, Callum — three short sentences.","Mark the unknown without drama: 'Callum I haven't seen since 4 — I'll radio him.'","Numbered answers under pressure read as control."],"focus":["structure","concision"],"placeholder":"Booking's confirmed for six. Ice arrived at 4. Callum I haven't seen since his break — I'll radio him now."},
    {"id":"pressure-svc-early-09","level":"early","profession":"service","title":"She's right and you're wrong","scenario":"You told a customer firmly that the offer ended Sunday. She pulls up the store's own website: it runs to Friday. She's right. The next ten seconds decide whether this becomes a story she tells about you or about how well you handled it.","task":"Script the concession: fast, clean, and without a heap of self-flagellation.","tips":["Concede in the first sentence — 'You're right, and I was wrong.'","Fix beats apology volume: apply the offer now, thank her for the catch.","Don't over-grovel; it makes her comfort YOU."],"focus":["audience","impact"],"placeholder":"You're absolutely right — it does run to Friday, and I had it wrong. Let me put that through at the offer price right now."},
    {"id":"pressure-svc-early-10","level":"early","profession":"service","title":"The reporter at the cordon","scenario":"You're on security after an incident in the shopping centre, and someone with a phone out says they're from the local paper: 'What happened? Was anyone hurt?' You know some of it. Your job is to say nothing newsworthy — without the clip of you saying 'no comment' looking shifty.","task":"Script a 1-2 sentence response that's polite, gives nothing, and points to the right person.","tips":["Have the line ready: 'I can't discuss it — our management team will give a statement.'","Never speculate, confirm, or deny details — 'was anyone hurt' is a trap in both directions.","Calm and courteous IS the message on camera."],"focus":["audience","precision"],"placeholder":"I'm not able to discuss it — the centre's management team will make a statement. They're the right people to ask."},
    {"id":"pressure-svc-early-11","level":"early","profession":"service","title":"Holding the wait time","scenario":"You quoted forty minutes for a table. The man returns at minute fifteen: 'Surely it's quicker than that now?' Then again at twenty-five. The number hasn't changed. Caving to pressure with a happier number just moves the anger to minute forty.","task":"Script the calm second response that holds the honest number.","tips":["Repeat the truth without new decoration: 'still about twenty-five minutes.'","Don't apologize for reality each time — once was enough.","Add the one honest sweetener you control: first round at the bar, or first table that fits."],"focus":["precision","impact"],"placeholder":"It's still looking like twenty-five minutes — the number's real, I promise I'm not padding it. You're next for a four-top."},
    {"id":"pressure-svc-early-12","level":"early","profession":"service","title":"'Why wasn't I called sooner?'","scenario":"You're a carer. The client's daughter, upset, asks why she heard about this morning's dizzy spell at 2pm and not 10am. The truth: your protocol is to call the office first, and the office calls family. She's asking you to defend a system while she's frightened.","task":"Give a 2-3 sentence answer: acknowledge the fear, answer directly, explain the path once.","tips":["Her fear first — one sentence, genuine.","Then the direct answer: I reported it at 10:05; the office contacts family.","Offer the improvement path: her number can be added for direct alerts if the plan allows."],"focus":["audience","clarity"],"placeholder":"You're right to want to know straight away — I'm sorry that gap frightened you. I reported it to the office at 10:05; they handle family calls, and I can ask whether you can be listed for direct contact."},
    {"id":"pressure-svc-early-13","level":"early","profession":"service","title":"Quote the price, then stop talking","scenario":"A customer asks what the deep-clean package costs. You say '$180' — and then, into the silence, you keep going: 'but we could maybe do something, there's sometimes a discount, I could ask…' You've negotiated against yourself before she said a word.","task":"Script the answer: the price, one line of what it includes, then the stop.","tips":["Silence after a price is thinking, not objection — let it happen.","If you must fill it, fill it with value, not discounts.","The next sentence is hers. Practice not taking it."],"focus":["concision","impact"],"placeholder":"That's $180, which covers the full three-bedroom deep clean including ovens and windows."},
    {"id":"pressure-svc-early-14","level":"early","profession":"service","title":"The interview question you can't answer","scenario":"In your shift-supervisor interview, the manager asks: 'What would you say our busiest till hour costs us in queue walkaways?' You have no idea — it's a number you've never seen. Bluffing a statistic in an interview is how offers die.","task":"Give the honest answer that shows how you'd find out and what you DO know.","tips":["Clean admission, zero waffle: 'I don't know that number.'","Immediately show the method: till data against door counts would tell us.","Bridge to adjacent knowledge you do have: what you see at the 5pm peak."],"focus":["clarity","structure"],"placeholder":"I don't know that number. I'd pull till volumes against the door counter to get it — what I can tell you from the floor is we lose people when the queue passes five."},
    {"id":"pressure-svc-early-15","level":"early","profession":"service","title":"The police ask what you saw","scenario":"Two customers fought in the car park and an officer is taking your account. You saw the shove but not what started it — though you have a strong hunch. Under the pressure of being asked, hunches love to dress up as facts.","task":"Give a 2-3 sentence account that keeps observed and assumed strictly apart.","tips":["Only what your eyes and ears got: 'I saw the taller man shove the other against the van.'","If asked about before: 'I didn't see what started it' — full stop, hunch stays home.","'I don't know' to police is a complete and excellent answer."],"focus":["precision","clarity"],"placeholder":"I saw the taller man shove the other against the white van at about 6:20 — I was by the trolleys, maybe ten meters away. I didn't see what started it."},
    {"id":"pressure-svc-early-16","level":"early","profession":"service","title":"'Whose fault was the double-booking?'","scenario":"Two families arrived for the same table and the manager asks you directly: 'Whose mistake was this?' You know Priya took both bookings — during the hour the system was crashing and rebooting. A one-name answer would be true and unfair at once.","task":"Answer the question honestly without hanging a colleague out to dry.","tips":["Answer with the mechanism, not just the name: both bookings landed during the system crash.","Facts, not shields: don't lie to protect anyone — context isn't a cover-up.","Steer to the fix: paper backup during outages."],"focus":["audience","impact"],"placeholder":"Both bookings went in during Tuesday's system crash — Priya took them, and the reboot wiped the first from the screen. A paper backup during outages would stop it recurring."},
    {"id":"pressure-svc-early-17","level":"early","profession":"service","title":"'Is the fish fresh?' — the question behind it","scenario":"A customer eyeing the counter asks 'is the fish fresh?' No one answers 'no' to that, and she knows it — which is why the literal answer is worthless. The real question is: which one should I trust enough to buy today?","task":"Answer the underlying question in 1-2 sentences with something specific.","tips":["Specifics are the only credible answer: 'the mackerel came in this morning.'","Steer honestly — including away: 'the plaice is day two; I'd grill it tonight, not tomorrow.'","One honest steer earns ten return visits."],"focus":["audience","precision"],"placeholder":"The mackerel and the hake both landed this morning — the mackerel's the one I'd take home today."},
    {"id":"pressure-svc-early-18","level":"early","profession":"service","title":"'That can't be right' — defend the count","scenario":"You reported 14 expired items pulled from the fridge aisle, and the deputy manager scoffs in front of two colleagues: 'Fourteen? That can't be right, we checked Monday.' You counted them into a crate an hour ago. Volume won't win this; evidence will.","task":"Script the calm 1-2 sentence reply that stands its ground with proof.","tips":["Don't restate louder — restate with the evidence: the crate is in the back, dates up.","Absorb the doubt without absorbing the framing: 'it surprised me too.'","Offer the walk: 'come count them with me' ends the debate."],"focus":["precision","impact"],"placeholder":"It surprised me too — they're in a crate in the back with the dates facing up. Come have a look; it's a two-minute count."},
    {"id":"pressure-svc-early-19","level":"early","profession":"service","title":"The four-part question, untangled","scenario":"A wedding client on the phone, audibly stressed, asks in one breath: can the venue do the earlier start, will the cleaning crew finish in time, does the quote include the extra hours, and who'll be on site on the day? Answering as a blob guarantees a second stressed call.","task":"Structure the spoken answer: name the four parts, then take them one by one.","tips":["Signpost first: 'four questions there — let me take them in order.'","One sentence per answer; flag any you owe her: 'the quote I'll confirm by email today.'","The structure itself is what calms her down."],"focus":["structure","clarity"],"placeholder":"Four things there — let me take them in order. Yes to the earlier start."},
    {"id":"pressure-svc-early-20","level":"early","profession":"service","title":"'Can't you make an exception?'","scenario":"The spa's last appointment is 7pm and a hotel guest, polite but persistent, wants 8:30 'just this once.' The therapist's shift and the law on her hours make the answer genuinely no. Persistent-polite is the hardest pressure there is.","task":"Give the no in 1-2 sentences: direct, warm, with the best real alternative.","tips":["Say the actual word: 'I can't tonight' — vague deflection invites round two.","One true reason, briefly: our therapist's hours are fixed.","Move fast to what you CAN do: 8am slot, held now, first of the day."],"focus":["audience","concision"],"placeholder":"I can't tonight — our therapist's hours are fixed and 7 is genuinely the last slot. What I can do is hold tomorrow's 8am for you right now."},
    {"id":"pressure-svc-early-21","level":"early","profession":"service","title":"The on-the-spot estimate","scenario":"The owner catches you restocking and asks, 'Rough guess — how many covers Saturday if this weather holds?' You COULD blurt a number. A number with a basis is worth ten times a number without one, and takes five more seconds.","task":"Give the spoken estimate: a range, the basis, and what would change it.","tips":["Ranges are honest: 110 to 130, not '120ish, dunno.'","Show one line of basis: last two sunny Saturdays ran 115 and 128.","Name the swing factor: the market brings 20 more if it's on."],"focus":["precision","structure"],"placeholder":"I'd say 110 to 130 — the last two sunny Saturdays did 115 and 128, and the street market adds about 20 when it's on."},
    {"id":"pressure-svc-early-22","level":"early","profession":"service","title":"The 10pm group-chat grenade","scenario":"The manager posts in the staff chat at 10pm: 'Freezer door was found open AGAIN tonight. WHO left it??' You closed the freezer at 6 — and saw the evening baker go in after you. Replying angry, defensive, or accusatory all make tomorrow worse.","task":"Write the reply that states your facts calmly and moves it off the group stage.","tips":["Just your verifiable piece: closed and checked it at 6, per the checklist.","Name what you saw without charging anyone: others accessed it after my shift.","Suggest the offline path: happy to talk tomorrow — group chats convict nobody fairly at 10pm."],"focus":["clarity","impact"],"placeholder":"I closed and latch-checked it at 6 when I signed the checklist — there were evening bakes after that. Happy to help figure it out tomorrow."},
    {"id":"pressure-svc-early-23","level":"early","profession":"service","title":"'What would you fix first?'","scenario":"The regional manager, mid-walkthrough, stops and asks you directly: 'If you ran this branch, what's the first thing you'd fix?' Ten seconds of um is a verdict. So is a safe non-answer like 'nothing major, really.'","task":"Give the direct 2-sentence answer: one specific fix, one concrete reason.","tips":["Have a real answer — floor staff always do; trust yours.","Specific and fixable beats big and vague: the delivery-time clash, not 'morale.'","One reason with a number if you have one: it eats two staff-hours every Tuesday."],"focus":["impact","concision"],"placeholder":"The Tuesday delivery slot — it lands mid-rush and pulls two people off the floor for an hour. Moving it to 7am would fix our worst morning of the week."},
    {"id":"pressure-svc-early-24","level":"early","profession":"service","title":"'Is it true Sam got fired?'","scenario":"A regular customer leans over the counter: 'So is it true Sam got fired for stealing?' You know some of the story. Every answer feels wrong: confirming gossips, denying lies, 'no comment' confirms it anyway. There's a fourth option: a clean boundary, warmly held.","task":"Script the 1-2 sentence response that declines without confirming, denying, or freezing.","tips":["The boundary, stated like it's obvious: 'that's Sam's business, not mine to share.'","Warm redirect immediately after — the usual order, the weather, anything.","Consistency is the trick: same answer no matter what you know."],"focus":["audience","precision"],"placeholder":"Ah, that's Sam's story to tell, not mine — I stay out of it. Now, the usual, or are you feeling adventurous?"},
    {"id":"pressure-svc-early-25","level":"early","profession":"service","title":"The broken record, gracefully","scenario":"A customer wants a cash refund for an item bought with a gift card. Policy says gift card refund only. You've explained it once, kindly. He's now re-asking the same question louder, hoping version three of your answer will be different.","task":"Script your third response: same answer, same warmth, zero new concessions.","tips":["Repeat the decision in nearly the same words — variation reads as negotiation.","Keep the temperature flat; his volume isn't yours to match.","Close with the choice: 'gift card refund or exchange — which works better for you?'"],"focus":["concision","impact"],"placeholder":"It's the same answer, I'm afraid — refunds go back onto the gift card. Gift card or an exchange: which works better for you?"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-svc-early-01","level":"early","profession":"service","title":"Before and after: the pickup shelf","scenario":"You want the café to add a dedicated pickup shelf for app orders. Your draft pitch is a feature list: 'a shelf, some labels, maybe a sign.' What sells a change is the before and after: the crowd at the till versus a clean flow.","task":"Write a 3-sentence pitch: the 'now' picture, the 'after' picture, the tiny cost between them.","tips":["Paint today first: app customers shouting names over the till queue.","Then the after: grab-and-go without a word.","The gap between the pictures is the pitch — the shelf is just the bridge."],"focus":["impact","structure"],"placeholder":"Right now every app customer pushes through the till queue shouting their name. With a labeled shelf by the door, they walk in, grab, and go."},
    {"id":"narrative-svc-early-02","level":"early","profession":"service","title":"The near-miss that makes it real","scenario":"You've reported the wobbly stockroom ladder twice as a line item and it's still there. Yesterday it skidded while Ana was on the third step — she caught the shelf. The fact was ignorable; the story isn't.","task":"Write a 3-sentence message that uses the moment to get the ladder replaced this week.","tips":["Tell the ten-second story: Ana, third step, the skid, the grab.","One human detail does what three reports didn't.","Land on the ask with a date: replaced before Friday's delivery."],"focus":["impact","audience"],"placeholder":"Yesterday the stockroom ladder skidded with Ana on the third step — she caught herself on the shelving. That's the third report on this ladder; can we have it replaced before Friday's delivery?"},
    {"id":"narrative-svc-early-03","level":"early","profession":"service","title":"The product customers keep asking for","scenario":"You're sure the shop should stock the gluten-free bread people request — you've been asked eleven times this month and you started writing them down. A tally is evidence; a customer's face is persuasion. You have both.","task":"Write a 3-4 sentence pitch combining the tally with one specific customer moment.","tips":["Lead with the number: eleven requests, four weeks, one product.","Add one face: the dad who drives past us to the health store every Saturday.","Finish with the low-risk trial: one case, four weeks, track it."],"focus":["impact","precision"],"placeholder":"Eleven customers asked for gluten-free bread this month — I kept a tally. One dad told me he does the rest of his shop here, then drives to the health store just for bread."},
    {"id":"narrative-svc-early-04","level":"early","profession":"service","title":"Answer the objection before it lands","scenario":"You want to close the hotel bar's outdoor terrace at 10pm instead of 11 — the last hour is two tables and three noise complaints. You know exactly what the manager will say: 'that's lost revenue.' If you don't address it, it ends the conversation.","task":"Write a 3-4 sentence proposal that raises and answers the revenue objection yourself.","tips":["Name it before she does: 'the obvious worry is losing the last hour's sales.'","Then the counter-math: two tables' drinks versus comped breakfasts for noise complaints.","Raising the objection yourself is what makes you sound like management."],"focus":["structure","impact"],"placeholder":"I'd close the terrace at 10 instead of 11. The obvious worry is lost sales — but the last hour averages two tables, and this month their tabs total less than the three breakfasts we comped for noise."},
    {"id":"narrative-svc-early-05","level":"early","profession":"service","title":"The dessert, sold as a story","scenario":"The kitchen wants the new baked cheesecake pushed tonight. The script you were given — 'can I tempt you with our delicious homemade cheesecake?' — is wallpaper; every restaurant says it. What sells is one specific, true detail told like you mean it.","task":"Script your 1-2 sentence table pitch built on a concrete detail, not adjectives.","tips":["Find the tellable fact: baked this afternoon, burnt-honey top, the chef's nan's recipe.","'Delicious' is a claim; 'we sold out by 9 last night' is a story.","Say it like a tip between friends, not an announcement."],"focus":["audience","impact"],"placeholder":"One thing before I take these plates — the cheesecake came out of the oven at four and last night it was gone by nine. There are three slices left."},
    {"id":"narrative-svc-early-06","level":"early","profession":"service","title":"Persuading a coworker, in their currency","scenario":"You need Dana to swap her Saturday morning for your Sunday close. Your draft is all about why YOU need it. Dana hates early starts, has a Sunday gym class she keeps missing, and owes you nothing. The case that works is built out of her reasons.","task":"Write the swap request framed around what Dana gets.","tips":["Open with her win: a Saturday lie-in and her Sunday morning back.","Your reason gets one clause, not the whole message.","Make the yes effortless: you'll do the rota paperwork today."],"focus":["audience","impact"],"placeholder":"Fancy a Saturday lie-in? If you take my Sunday close, I'll take your Saturday 7am — you'd finally make that gym class, and I'll sort the rota change today."},
    {"id":"narrative-svc-early-07","level":"early","profession":"service","title":"Three incidents, one arc","scenario":"You want the manager to rerun manual-handling training. Your evidence is three moments across a month: a dropped keg, Marta's tweaked back, a near-miss with the cellar hatch. Listed as bullet points they're noise; told as an arc, they're one story heading somewhere worse.","task":"Write a 4-sentence case that strings the three moments into one direction, ending in the ask.","tips":["Sequence them in time — 'first… then… last week…' builds the trajectory.","Name where the arc points: the next one is an injury claim, not a near-miss.","The training ask should land as the obvious ending to the story."],"focus":["structure","impact"],"placeholder":"Three moments from the last month, in order: a dropped keg in week one, Marta's back in week three, and last Friday the cellar hatch nearly took Josh's fingers."},
    {"id":"narrative-svc-early-08","level":"early","profession":"service","title":"The walker, framed as freedom","scenario":"You're a carer and Mrs. H refuses the walker her physio recommended — 'those are for old people.' Pushing the safety argument has failed twice; to her it's a symbol of decline. The persuasion that works reframes it around what she keeps, not what she admits.","task":"Script a 2-3 sentence conversation opener that frames the walker around her independence.","tips":["Anchor to what she wants: the garden, the shop on the corner, no waiting for help.","Never argue with the feeling — reframe the object: it's how you go alone.","Small trial, her control: just to the gate and back, once."],"focus":["audience","impact"],"placeholder":"You know what I keep thinking? With that thing you could get to your roses without waiting for me — it's not about being careful, it's about going where you want, when you want."},
    {"id":"narrative-svc-early-09","level":"early","profession":"service","title":"Book direct next time","scenario":"A lovely couple at checkout booked through a third-party site — which took a cut and gave them the worst room category. The hotel wants guests booking direct. A leaflet won't do it; twenty honest seconds at the desk might.","task":"Script the 2-sentence pitch at checkout: their benefit, concretely, no corporate plea.","tips":["Their win, not the hotel's: same price direct, but room choice and free late checkout.","Tie it to their actual stay: 'you'd have had the courtyard side.'","One sentence of pitch, one of how — then let it go."],"focus":["audience","concision"],"placeholder":"Next time, book with us directly — same price, but you pick your room and get late checkout free. You'd have had the quiet courtyard side this weekend."},
    {"id":"narrative-svc-early-10","level":"early","profession":"service","title":"The break rota, before and after","scenario":"Breaks currently start when someone 'finds a moment' — which means the quiet worker skips theirs and the till goes unmanned at random. You want fixed break slots. To the team this sounds like more rules, unless the after-picture is theirs.","task":"Write a 3-sentence pitch to the team: today's mess, tomorrow's version, what each person gains.","tips":["Describe the current pain they all recognize: the 3pm stare-off over who goes first.","The after is personal: your break at YOUR time, protected, every shift.","'More structure' repels; 'nobody loses their break again' persuades."],"focus":["structure","clarity"],"placeholder":"You know the 3pm stand-off where nobody takes their break because it's 'busy'? With fixed slots, your fifteen minutes is yours — printed, protected, every shift."},
    {"id":"narrative-svc-early-11","level":"early","profession":"service","title":"The tip jar goes contactless","scenario":"You want the café to trial a contactless tip point — hardly anyone carries cash and the jar's been near-empty for a year. The owner's reflex objection is cost and fuss. You've done the homework: the reader is $19/month and the barista college up the road doubled tips with one.","task":"Write a 3-4 sentence pitch that lands the objection's answer inside the story.","tips":["Start with the shared observation: the jar's been holding the same $4 since spring.","One proof point from the real world beats three projections.","Frame the trial as reversible: one month, $19, cancel anytime."],"focus":["impact","precision"],"placeholder":"That tip jar has held the same four dollars since spring — nobody carries cash. A contactless reader is $19 a month; the kiosk by the college put one in and tips doubled."},
    {"id":"narrative-svc-early-12","level":"early","profession":"service","title":"'We had this last week' — the calming story","scenario":"A guest's booking deposit hasn't shown in her banking app and she's spiraling toward panic at the front desk. You saw this exact thing last Tuesday: the bank's pending queue, cleared by morning. A short true story calms faster than any policy recital.","task":"Script the 2-3 sentence response that uses last week's case to reassure — plus the backstop.","tips":["The story does the reassuring: 'this exact thing, last Tuesday, cleared overnight.'","Keep it short — a story that rambles reads as deflection.","Always attach the backstop: if it's not there by 10am, here's my direct line."],"focus":["audience","clarity"],"placeholder":"This exact thing happened to a guest last Tuesday — the bank holds it as pending and it cleared by morning. If yours isn't showing by 10am, call me directly and I'll sort it from our end."},
    {"id":"narrative-svc-early-13","level":"early","profession":"service","title":"One face for forty complaints","scenario":"Your monthly summary says 'wait-time complaints up 40%' and it's landing like every other statistic: nodded at, filed. In your notebook is Mrs. Okafor, who waited 55 minutes for her click-and-collect order with frozen food thawing in the bag, and said quietly, 'I won't do this again.'","task":"Write a 3-sentence version pairing the number with the one customer who makes it mean something.","tips":["The number proves it's a pattern; the person proves it matters — you need both.","Use her real details: 55 minutes, thawing bag, the quiet 'I won't do this again.'","End where the story points: fixing the collection desk's 4-6pm staffing."],"focus":["impact","precision"],"placeholder":"Wait complaints are up 40% this month — but here's what that looks like: Mrs. Okafor stood 55 minutes for her collection while her frozen food thawed, and left saying 'I won't do this again.'"},
    {"id":"narrative-svc-early-14","level":"early","profession":"service","title":"Selling the checklist to the team","scenario":"Head office mandated a new closing checklist, and your job at the huddle is to get the team to actually use it — not eye-roll it into a drawer. 'We have to' is compliance; a reason they feel is persuasion. You know the reason: the freezer left open last month cost someone a very bad morning.","task":"Script a 3-sentence huddle pitch that sells the checklist on the team's own experience.","tips":["Anchor to the shared memory: everyone remembers the freezer morning.","Frame the checklist as protection, not surveillance: it's how nobody carries that alone again.","Keep the ask small: two minutes, tick boxes, done."],"focus":["audience","impact"],"placeholder":"Remember the freezer morning — four bins of stock and Jess getting the 6am call? This list is two minutes at close, and it means no one ever carries that alone again."},
    {"id":"narrative-svc-early-15","level":"early","profession":"service","title":"Walking him out, with options","scenario":"You're venue security and a man who's had too many is refusing to leave — planted at the bar, not aggressive yet, audience forming. Force is the last resort and the worst story. What moves people is choices framed so that walking out is the good one.","task":"Script the 2-3 sentence approach: low voice, his dignity intact, two options where leaving wins.","tips":["Give him a story he can save face inside: 'let's call it a night while it's still a good one.'","Two choices, both yours: walk out with me now for a taxi, or this becomes formal.","Low and slow — the audience should see nothing worth filming."],"focus":["audience","clarity"],"placeholder":"Mate, it's been a good night — let's keep it one. Walk out with me now and I'll get you a taxi, or we do this the formal way. First one's better, and it's yours to pick."},
    {"id":"narrative-svc-early-16","level":"early","profession":"service","title":"The cost of the broken door","scenario":"The automatic entrance door has been broken for three weeks; your manager's repair request is 'pending with head office.' You want to arm her with a better story than 'it's inconvenient' — because somewhere up the chain, inconvenient means never.","task":"Write 3 sentences she can forward: what the broken door costs per week, told concretely.","tips":["Count what head office counts: the wheelchair user who couldn't enter, buggies turning away.","Attach a number where you can: you've counted six turnaways this week alone.","End with the flip: the repair quote is less than one week of that."],"focus":["impact","structure"],"placeholder":"The broken door isn't an inconvenience — it's turning customers away. This week alone I counted six people with buggies or wheelchairs who couldn't get in; the repair quote is less than what they'd have spent."},
    {"id":"narrative-svc-early-17","level":"early","profession":"service","title":"The ramp, argued from one Tuesday","scenario":"You're a carer and the loose paving at your client's front path means her wheelchair can't safely leave the house. Your requests to the housing office have been form-words: 'urgent repair needed.' What you haven't sent is what last Tuesday actually looked like.","task":"Write a 3-4 sentence message that makes one specific Tuesday do the persuading.","tips":["Show the scene: the day center van waiting, the chair stuck at the third slab, her going back inside.","Concrete stakes: she's missed the center — her only outing — two weeks running.","Then the ask, dated: assessment this week, or she misses a third."],"focus":["audience","impact"],"placeholder":"Last Tuesday the day-center van waited fifteen minutes while I tried to get Mrs. H's wheelchair past the broken slab — we couldn't, and she went back inside. That's two weeks running she's missed her only outing."},
    {"id":"narrative-svc-early-18","level":"early","profession":"service","title":"From spec sheet to Saturday morning","scenario":"A couple is choosing between two mattresses and you're reciting the spec sheet: pocket springs, gel layer, 32cm depth. Their eyes say the words aren't landing. Specs describe the object; a story describes their life with it.","task":"Rewrite your pitch as 2 sentences that put them inside the difference.","tips":["Translate each spec into a felt moment: gel layer = not waking up when he turns over.","Use their details — they mentioned a toddler who invades the bed at 6am.","One picture, one honest steer, stop selling."],"focus":["audience","clarity"],"placeholder":"The real difference is this one doesn't move when your partner does — when your little one lands at 6am, one of you might actually sleep through it."},
    {"id":"narrative-svc-early-19","level":"early","profession":"service","title":"Save the soup","scenario":"Head office is cutting the homemade soup from the menu — 'low sales.' You know why the number looks bad: it's hidden on page three and still sells 40 bowls a week to the lunch regulars, who order it by habit without a menu. The delist decision is Friday.","task":"Write a 3-4 sentence case to your manager: the number in context, the loyal-regulars story, the alternative to test.","tips":["Reframe the stat: 40 bowls with zero menu presence is strength, not weakness.","Put faces on it: the building-site crew that comes in for it daily at noon.","Offer the test that beats deletion: front-page it for a month, then decide."],"focus":["precision","impact"],"placeholder":"Before the soup goes — it sells 40 bowls a week from page three of the menu, with no photo and no board mention. The site crew orders it by name every day at noon."},
    {"id":"narrative-svc-early-20","level":"early","profession":"service","title":"Persuading him to report the cut","scenario":"A coworker sliced his hand on the broken slicer guard and wants to just wrap it and carry on — 'it's nothing, I don't want the paperwork fuss.' You want it reported: for his sake if it worsens, and because the guard will cut the next person. He's the persuasion target, not the manager.","task":"Script the 2-3 sentence peer-to-peer case that gets him to report it.","tips":["Argue his interest first: unreported means no cover if it gets infected next week.","Then the next-person story: the guard's still broken and Ana's on the slicer tomorrow.","Shrink the cost: the form is five minutes and you'll do it with him."],"focus":["audience","impact"],"placeholder":"Wrap it, sure — but report it too. If that gets infected next week, unreported means you're on your own; and Ana's on that slicer tomorrow with the same broken guard. Five minutes, I'll fill the form in with you."},
    {"id":"narrative-svc-early-21","level":"early","profession":"service","title":"The renewal pitch, shown not told","scenario":"Your cleaning company's contract for the office building renews next month and the client is 'reviewing options.' Your boss wants a paragraph for the renewal email from your crew. You've got the receipts: complaints down from five a month to zero since your team took floor three.","task":"Write 2-3 sentences for the email: the before/after with numbers, plus one visible detail people mention.","tips":["Before-and-after with the client's own metric: their complaint tickets, five to zero.","Add the human trace: reception mentions the lobby glass every Monday.","Let the contrast sell — no adjectives about yourselves."],"focus":["impact","precision"],"placeholder":"When we took over floor three in January, the building logged five cleaning complaints a month; the last ninety days, zero. Your reception team mentions the lobby glass most Mondays —"},
    {"id":"narrative-svc-early-22","level":"early","profession":"service","title":"The raise, objection-first","scenario":"You're asking for a raise, and you already know the manager's move: a sympathetic wince and 'the budget's tight this quarter.' If the conversation starts there, it ends there. So start there yourself — with what you've taken off her plate this year.","task":"Write the 3-4 sentence opener that names the budget objection and makes your case anyway.","tips":["Front-load it: 'I know budgets are tight, so I'll be specific about what's changed.'","Your case is delta, not tenure: keyholding, training three hires, the Sunday close.","End on a number and a date, not 'whatever's possible.'"],"focus":["structure","impact"],"placeholder":"I know the budget's tight, so let me be specific about what's changed since my rate was set: I hold keys, I've trained three hires, and I've run every Sunday close since March."},
    {"id":"narrative-svc-early-23","level":"early","profession":"service","title":"Getting the kitchen to change, as an ally","scenario":"Friday mains are batching out of the kitchen — four tables' plates in one window crush, then nothing for twenty minutes. You want the kitchen to stagger the fire times. March in with 'you're doing it wrong' and you'll eat cold plates for a month.","task":"Script the 2-3 sentence approach to the head chef: their problem, your observation, joint fix.","tips":["Open inside their interest: the crush means their food dies under the lamp.","Bring floor intel as a gift, not a verdict: 'from the floor, here's the shape of it.'","Propose together-language: 'what if we fired the four-tops five minutes apart?'"],"focus":["audience","impact"],"placeholder":"Chef — your Friday plates are dying under the lamp, and it's killing me too. From the floor it looks like all four big tables fire at once; what if we staggered them five minutes apart?"},
    {"id":"narrative-svc-early-24","level":"early","profession":"service","title":"The noticeboard appeal that gets names","scenario":"You need four volunteers for the charity bake sale shift on the 14th, and the standard noticeboard plea — 'volunteers needed for community engagement event' — got zero names last time. You have five lines and a pen on a string.","task":"Write the short appeal that actually collects names.","tips":["Say what it really is: two hours, Saturday morning, selling cake for the children's ward.","Make the first move tiny: 'write your name, I'll sort the rest.'","One warm true detail beats a mission statement: last year we raised $600 in a morning."],"focus":["concision","impact"],"placeholder":"Sat 14th, 10-12: help sell cakes for the children's ward. Last year we raised $600 in one morning. Write your name below — I'll handle everything else."},
    {"id":"narrative-svc-early-25","level":"early","profession":"service","title":"'We've always done it this way'","scenario":"You've proposed pre-rolling the cutlery during dead hours instead of at close, and the longest-serving server shuts it down: 'we've always done it at close.' She's not wrong that it works — and she carries the room. Winning the argument loses the person; the pitch has to honor what came before.","task":"Script a 2-3 sentence reply that respects the old way while making the case to trial the new one.","tips":["Concede what's true first: the close routine has worked for years.","Frame change as circumstances, not correction: closes got 30 minutes longer since the kitchen hours changed.","Ask for a trial she controls: her section, one week, her verdict."],"focus":["audience","structure"],"placeholder":"The close routine's worked for years — no argument. But closes run half an hour longer since the kitchen change, and that's new. Trial it in your section for a week and you call it?"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-svc-early-01","level":"early","profession":"service","title":"The lost booking, headline first","scenario":"A family of four is at the front desk, bags in hand, and their booking isn't in the system — and the hotel is full. Your instinct is to narrate your searching ('let me just try one more thing…') for five minutes of false hope. They need the headline, then the help.","task":"Script the 2-3 sentences that deliver the bad news first and the plan immediately after.","tips":["Headline in sentence one: we don't have your booking and we're full tonight.","No suspense — every minute of typing theater makes it worse.","The plan is the comfort: sister hotel, rate honored, taxi paid."],"focus":["clarity","audience"],"placeholder":"I have bad news and a plan. Your booking isn't in our system and we're full tonight — but our sister hotel two streets over has a room, we'll honor your rate, and the taxi's on us."},
    {"id":"hard-svc-early-02","level":"early","profession":"service","title":"Declining the swap, cleanly","scenario":"A coworker asks you to take her Friday night. You could — technically — but it's your first free Friday in a month and you're keeping it. Your draft is four sentences of excuses that invite her to solve each one. A clean no needs no case file.","task":"Write the 1-2 sentence decline: clear, warm, unexcused.","tips":["'I can't this time' is a complete reason.","Manufactured excuses get remembered and checked — warmth doesn't need them.","Soften with future, not fiction: 'ask me again, I usually can.'"],"focus":["clarity","concision"],"placeholder":"I can't this Friday — I'm keeping that one. Ask me next time though, I can usually help."},
    {"id":"hard-svc-early-03","level":"early","profession":"service","title":"Handing in your notice","scenario":"You've accepted a job closer to home and need to tell the manager who trained you, championed you, and will take this personally. You owe her directness, not a mumbled exit — and the temptation to soften it into vagueness ('I've just been thinking about some stuff…') helps neither of you.","task":"Script the first 2-3 sentences of the conversation: the news, the date, the genuine thanks.","tips":["Say the actual thing in sentence one: 'I'm resigning — my last day would be the 30th.'","Gratitude belongs here, specific and true: what she actually taught you.","Don't blur the message to spare the moment; clarity is the respect."],"focus":["clarity","impact"],"placeholder":"I wanted you to hear this from me first: I've accepted a job closer to home, and my last day would be the 30th. You taught me most of what I know here —"},
    {"id":"hard-svc-early-04","level":"early","profession":"service","title":"Feedback on the handover, not the person","scenario":"The carer on the shift before yours leaves handover notes that keep missing medication times — twice you've had to phone the office to reconstruct the morning. You like her. The note you're about to send says 'your notes are always so vague' — a character verdict, not a fixable behavior.","task":"Rewrite as 2-3 sentences of specific, actionable feedback.","tips":["Name the behavior and instance, not the trait: Tuesday's note had no med times.","Say the consequence plainly: I gave the 2pm dose on a guess and a phone call.","End with the specific ask: times and doses on every note, even routine ones."],"focus":["audience","precision"],"placeholder":"Tuesday's handover didn't have the morning med times, and I had to call the office before giving the 2pm dose. Could you put times and doses on every note, even when it's routine?"},
    {"id":"hard-svc-early-05","level":"early","profession":"service","title":"The refund that isn't happening","scenario":"A customer's claim fails every check: no receipt, item from a different chain, visibly used for months. You've stretched policy for people before — this isn't one of those. A mushy 'I'm not really sure we can…' invites a fifteen-minute siege. The kind thing is the clear thing.","task":"Script the 1-2 sentence refusal: definite, courteous, done.","tips":["Definite words: 'I can't refund this' — not 'I don't think I can.'","One reason, once: it's not from our store.","Don't counterfeit hope with 'maybe try customer services' unless it's real."],"focus":["clarity","audience"],"placeholder":"I can't refund this one — it's not from our store, so there's nothing I can put it through against. That's a firm no, I'm sorry."},
    {"id":"hard-svc-early-06","level":"early","profession":"service","title":"The call no carer wants to make","scenario":"Your client fell this morning and this time she's been taken to hospital for an X-ray on her hip. You're calling her son — who you told after the LAST incident that she was fine. He'll hear the first five words and fill in the rest with worse. The first five words matter.","task":"Script the opening 2 sentences: what happened, where she is, her condition — no suspense, no minimizing.","tips":["Front-load the state she's in NOW: conscious, talking, being checked.","Then the event, plainly: she fell this morning; they're X-raying her hip.","Don't minimize to soothe — he needs to trust your reports after today too."],"focus":["audience","clarity"],"placeholder":"It's Sam — your mum is okay and talking, but she had a fall this morning and she's at St. Mary's getting her hip X-rayed. I'm with her now."},
    {"id":"hard-svc-early-07","level":"early","profession":"service","title":"Cancelling the thing they wanted","scenario":"Head office pulled the budget and the staff Christmas party is off. You're posting it in the group chat, and your draft buries the cancellation under four sentences of 'so as you know, things have been challenging this year…' Everyone will skim to the bad news anyway; make them dig and they'll resent the digging too.","task":"Write the 2-3 sentence announcement: news first, reason once, any silver lining honestly sized.","tips":["First sentence is the fact: the party's cancelled.","One sentence of reason, no corporate fog.","If there's a consolation (a shift drink, next year's promise), state it at its true size — don't inflate it."],"focus":["clarity","concision"],"placeholder":"The Christmas party is cancelled — head office pulled the events budget across all branches. It's rubbish news, no dressing it up. We'll do a first-round-on-me at the Swan after close on the 20th instead — smaller, but real."},
    {"id":"hard-svc-early-08","level":"early","profession":"service","title":"No to the boss, without the spiral","scenario":"Your manager asks you to cover Sunday — the third weekend ask this month. You're saying no, but your draft is a guilt spiral: three apologies, your whole life story, and a closing 'but I mean, if you're really stuck…' that undoes the no entirely.","task":"Rewrite as 1-2 sentences: a clear no that survives the follow-up push.","tips":["No backdoor: cut every 'but if you're really stuck.'","One apology maximum — it's a no, not a wrong.","You can acknowledge her problem without adopting it: 'I hope you find someone.'"],"focus":["concision","clarity"],"placeholder":"I can't do Sunday — I've got family plans I'm keeping. Hope you find cover; I'm back on my usual shifts Tuesday."},
    {"id":"hard-svc-early-09","level":"early","profession":"service","title":"Their favorite is gone for good","scenario":"Mrs. Petrov has bought the same rye loaf every Saturday for six years, and the bakery has discontinued it — the supplier closed. She's at the counter, and you're the one who has to tell her. It's a small loss that isn't small to her.","task":"Script the 2-sentence message: the news straight, the loss acknowledged, the nearest real alternative.","tips":["Tell her straight — dodging ('we're out today…') just reruns this scene next Saturday.","Let it be a loss for a beat: 'I know, six years of Saturdays.'","Offer the closest true substitute, honestly ranked: 'the sourdough rye is the nearest — not the same, but good.'"],"focus":["audience","clarity"],"placeholder":"Mrs. Petrov, I have to tell you straight — the rye is discontinued, our supplier closed down. The sourdough rye is the closest we have; it's not the same, but it's the one I'd pick."},
    {"id":"hard-svc-early-10","level":"early","profession":"service","title":"Reporting the shortcut, not the person","scenario":"A coworker has been propping the fire exit with a mop bucket during deliveries — genuinely dangerous, already warned once by you, still happening. Reporting it feels like snitching. But the report can be about a recurring hazard, not a prosecution of a friend.","task":"Write the 2-3 sentence report to your supervisor: the hazard, the pattern, no character assassination.","tips":["Report the behavior and the risk, not a verdict on the person.","Facts and dates: propped during Tuesday and Thursday deliveries, after we talked about it.","Include what you already did: raised it directly first — that's fairness, and say it plainly."],"focus":["precision","audience"],"placeholder":"The fire exit's been propped open with the mop bucket during deliveries — Tuesday and Thursday this week. I raised it directly with Chris after the first time; it's still happening, so I'm flagging it to you."},
    {"id":"hard-svc-early-11","level":"early","profession":"service","title":"'You're not ready yet' — with a path","scenario":"The new hire asked to run Friday's close solo, and he isn't ready — his till counts have needed correcting twice this week. A vague 'maybe soon!' feels kinder and teaches him nothing. The honest version needs specifics and a route, or it's just a door in the face.","task":"Script the 2-3 sentence answer: the no, the specific gap, the path to yes.","tips":["The no first, unhedged — 'not this Friday.'","The reason is a gap, not a flaw: two till-count corrections this week.","The path makes it feedback: three clean counts and a supervised close, then it's yours."],"focus":["audience","impact"],"placeholder":"Not this Friday — your till counts needed correcting twice this week, and the close stands on that. Get me three clean counts and one supervised close, and the next one's yours."},
    {"id":"hard-svc-early-12","level":"early","profession":"service","title":"The price increase letter","scenario":"Your cleaning business is raising prices 8% for the first time in three years — supplies and travel costs have jumped. You're writing to a dozen loyal householders. The draft you inherited hides the number in paragraph three and calls it 'a small adjustment to our pricing structure.' They'll all scan for one thing: what do I pay now?","task":"Write the 3-sentence version: the new price up front, the plain reason, the date it starts.","tips":["The number and date in sentence one — hunting for it breeds distrust.","One honest reason beats three corporate ones: our costs went up; we held out three years.","Thank them like you mean it, once, briefly."],"focus":["clarity","audience"],"placeholder":"From March 1st, your fortnightly clean goes from $90 to $97. Our supply and travel costs have risen steadily and we've held prices for three years — this keeps us sustainable. Thank you for staying with us; it means a lot."},
    {"id":"hard-svc-early-13","level":"early","profession":"service","title":"The behavior warning at the bar","scenario":"A guest at the hotel bar is getting loud — leaning into other tables, twice nearly toppling a stranger's drinks. He's a paying guest and not yet over any line, but he's one drink from it. The warning has to land now, before the eviction has to.","task":"Script the 1-2 sentence quiet word: respectful, unambiguous, consequences included.","tips":["Deliver it as information, not scolding: here's where this is heading.","Be concrete about the behavior — 'leaning into other tables' — not 'your attitude.'","State the consequence once, flatly: next step is I have to ask you to leave."],"focus":["audience","impact"],"placeholder":"A quiet word — you're leaning into other guests' tables and knocking drinks, and I need it to stop. If it carries on I'll have to ask you to leave, and I'd rather not."},
    {"id":"hard-svc-early-14","level":"early","profession":"service","title":"You broke it — say so first","scenario":"You knocked a framed photo off the hall shelf while vacuuming a client's home, and the glass cracked. Nobody saw. She's elderly, trusting, and might not notice for weeks. Which is exactly why the message you leave has to lead with it — found later, it becomes a theft of trust, not an accident.","task":"Write the note (or script the words) that owns it head-on: what happened, the apology, the fix.","tips":["First sentence: I broke it, vacuuming, today.","The fix is specific: replacement glass this week, at my cost.","Owning it before discovery is the whole difference between an accident and a secret."],"focus":["clarity","impact"],"placeholder":"I have to tell you something — I knocked the hallway photo down while vacuuming today and the glass cracked. I'm so sorry. I'll bring a new glass for the frame on Thursday, my treat."},
    {"id":"hard-svc-early-15","level":"early","profession":"service","title":"Telling the boss about the rota pattern","scenario":"Three of you have noticed the same thing: the weekend shifts everyone wants keep going to the same two people, who happen to be the manager's five-a-side teammates. Maybe it's coincidence. Saying 'you're playing favorites' is a grenade; saying nothing means it calcifies. There's a third way: the observable pattern, raised as a question.","task":"Script the 2-3 sentence conversation opener: pattern, not accusation; question, not verdict.","tips":["Bring the observable, leave the motive: 'the last six premium Saturdays went to the same two people.'","Ask for the mechanism, not a confession: 'could we rotate them or post them openly?'","Speak for yourself, not 'everyone's saying' — borrowed armies escalate things."],"focus":["audience","structure"],"placeholder":"Could I raise something about the rota? The last six Saturday day-shifts have gone to the same two people — I'd love a shot at those, and I wondered if we could rotate them or post them for anyone to claim."},
    {"id":"hard-svc-early-16","level":"early","profession":"service","title":"'Clock me in, yeah?' — the refusal","scenario":"A coworker running late texts you: 'Clock me in when you get there, yeah? 10 mins away.' It's time fraud — small, common, and career-ending if caught. He's your mate. The refusal needs to be instant, total, and still friendly at lunch.","task":"Write the text back: the no, the reason in plain words, the friendship intact.","tips":["Refuse the act, not the person: 'can't do that one, mate.'","Name it honestly once — that's the kind of thing people get sacked for — no sermon.","Offer the legitimate help: I'll tell them you're ten minutes out."],"focus":["clarity","impact"],"placeholder":"Can't do that one mate — clocking someone else in is sackable and I'm not risking us both. I'll tell them you're 10 out; just get here."},
    {"id":"hard-svc-early-17","level":"early","profession":"service","title":"The complaint TO the supplier","scenario":"The bakery's flour delivery driver reversed over the herb planters — again — then denied it despite the camera. You're writing the complaint your manager will send. Angry drafts feel great and achieve nothing; the effective version is specific, documented, and asks for exactly one thing.","task":"Write the 3-sentence complaint: incident with date and evidence, the pattern, the specific remedy.","tips":["Facts with receipts: date, time, and 'our camera footage shows the contact.'","Name the pattern in one line: second time in a month.","Ask for something checkable: replacement cost covered and a different approach route — not 'do better.'"],"focus":["precision","audience"],"placeholder":"On Tuesday the 14th at 6:40am, your delivery vehicle reversed into our front planters — our camera footage shows the contact clearly. This is the second incident in a month."},
    {"id":"hard-svc-early-18","level":"early","profession":"service","title":"The climbing kid","scenario":"A child is climbing the shelving in aisle 3 — the same shelving unit that has a 40kg bag of compost on top. His mother is right there, scrolling. Nobody enjoys correcting someone else's parenting in public; the sentence has to be about safety, not about her.","task":"Script the 1-2 sentence approach: the danger named, zero parenting judgment, warm exit.","tips":["Address her, frame the shelf as the villain: 'those units aren't anchored for climbing.'","Say the actual risk once: there's heavy stock up top.","Tone: same voice you'd use for 'your lights are on' — helpful, not corrective."],"focus":["audience","clarity"],"placeholder":"Excuse me — just so you know, those shelves aren't anchored and there's heavy stock on top, so I get nervous when kids climb them. Thanks so much."},
    {"id":"hard-svc-early-19","level":"early","profession":"service","title":"Announcing the cut hours","scenario":"The café is dropping Sunday trading from next month, which means everyone loses a shift's pay. You're telling the team at the huddle before the rota makes it obvious. The message has three duties: the fact, what it means for each person, and what's being done about it — in that order, no fog.","task":"Write the 3-4 sentence announcement covering fact, impact, and next step.","tips":["The decision first, dated: no Sunday trading from the 1st.","Translate to what they care about: that's one shift a week, roughly $90 for most of you.","The next step must be real: extra Saturday cover offered by seniority, sign-up sheet today."],"focus":["structure","audience"],"placeholder":"From the 1st we're closed Sundays — that's final, from ownership. For most of you it means one shift a week, around $90. The extra Saturday and delivery-day cover goes up on the sheet today, offered by seniority first."},
    {"id":"hard-svc-early-20","level":"early","profession":"service","title":"The promise you have to break","scenario":"You promised a customer her repaired necklace would be ready for her daughter's wedding this Saturday. The repairer just called: the part won't land until Tuesday. Every hour you delay telling her is an hour of options she loses. The call has to happen now, and lead with the miss.","task":"Script the call's first 3 sentences: the broken promise, the why in one line, the options you've built.","tips":["Say the miss in sentence one — 'it won't be ready Saturday' — before sorry, before why.","Bring options, not just apology: a loan piece from the display, or a refund and the repair free.","You made the promise; use 'I', not 'the repairer.'"],"focus":["clarity","impact"],"placeholder":"I'm calling with bad news I didn't want to leave until Friday: the necklace won't be ready for Saturday. The part's delayed to Tuesday — that's on me, I promised it. Here's what I can offer for the wedding —"},
    {"id":"hard-svc-early-21","level":"early","profession":"service","title":"Feedback up: the huddles are too long","scenario":"Your manager's pre-shift huddles have crept to twenty-five minutes — the floor opens late, and half of it is one topic looping. You're the one who's decided to say something. Upward feedback survives on the same rules as downward: specific, behavioral, with a suggestion attached.","task":"Script the 2-sentence private word: the observation with its cost, and one concrete suggestion.","tips":["Numbers over adjectives: twenty-five minutes, doors late twice this week — not 'they drag.'","Attach the fix so it's a proposal, not a gripe: three points, ten minutes, anything longer to the board.","Private, once, and let her own the decision."],"focus":["concision","audience"],"placeholder":"Could I offer one thought on huddles? They've hit twenty-five minutes and the doors opened late twice this week — I think three points in ten minutes would land better, with the rest on the board."},
    {"id":"hard-svc-early-22","level":"early","profession":"service","title":"The care hours that don't exist","scenario":"Your client's daughter wants to add a daily evening visit — her mum's evenings are lonely, and she's right that it would help. But the agency has no evening capacity in that area for at least two months, and you know it. Hinting 'we'll see what we can do' would be kinder-feeling and crueler.","task":"Write the 3-sentence reply: the honest no with timeframe, the reason, and the real alternatives.","tips":["The truthful shape: not 'no forever' but 'not for two months' — precision is kindness here.","One plain reason: no evening staff in the area right now.","Real alternatives only: the waitlist (join it today), the befriending service, a check-in call."],"focus":["audience","structure"],"placeholder":"I have to be straight with you: we can't staff an evening visit for at least two months — there's simply no evening capacity in the area right now. Here's what I can do today: put her on the waitlist, and connect you with the befriending service that does evening calls."},
    {"id":"hard-svc-early-23","level":"early","profession":"service","title":"Enforcing on a colleague","scenario":"You're the security guard, and the person propping the staff door open for smoke breaks is a colleague twice your age who's worked here fifteen years. He waves you off with 'relax, it's five minutes.' Enforcing rules on peers is harder than on strangers — and more watched.","task":"Script the 1-2 sentence line that holds the rule without humiliating him.","tips":["The rule is the heavy — let it be: 'I can't leave it propped, it's the one thing they check.'","Give him the out that keeps his dignity: I'll badge you back in myself.","Same rule, every person, every time — consistency is what makes it not personal."],"focus":["clarity","impact"],"placeholder":"Can't leave it propped, Ray — that door's the one thing they hang me for. Knock when you're done and I'll badge you straight back in."},
    {"id":"hard-svc-early-24","level":"early","profession":"service","title":"The comp that isn't coming","scenario":"A guest found the minibar missing two sodas at check-in — annoying, real, and fixed within ten minutes. At checkout he's demanding the whole night comped, 'or I write a review you won't like.' The fair amend is the minibar charge waived and a drink voucher. The night costs $240 and it isn't happening.","task":"Script the 2-3 sentence response: the no to the night, the fair amend offered, the review threat left unfed.","tips":["Match the amend to the harm, and say that's the principle: sodas, not the suite.","Don't negotiate with the review — acknowledge his right to write one and stay level.","Offer the amend like you mean it, because you do — it's fair, and fair is your ground."],"focus":["audience","precision"],"placeholder":"I won't comp the night — the issue was two missing sodas, fixed in ten minutes, and the amend should match that. I've waived the minibar charge and added a bar voucher. You're welcome to review your stay however you see it; I'm comfortable we've been fair."},
    {"id":"hard-svc-early-25","level":"early","profession":"service","title":"The one nobody wants to have","scenario":"A teammate you genuinely like has a body-odor problem, and it's now affecting the team: two customers commented, and coworkers are trading shifts to avoid the section next to his. Your manager asked you — his closest friend on staff — to have the quiet word. There is no painless version; there is a kind one.","task":"Script the 2-3 sentence private conversation: direct, specific enough to act on, dignity intact.","tips":["Privately, once, plainly — dropping hints for weeks is the cruel option.","Say it as a fixable thing, because it is: 'this is awkward and small and I'd want to be told.'","No committee: 'I noticed', not 'people are saying' — even if they are."],"focus":["audience","clarity"],"placeholder":"This is awkward, so I'll just say it because I'd want you to tell me: I've noticed body odor the last few shifts. It's small and fixable and I promise it stays between us — I just didn't want you not knowing."}
  ],
  "putting-it-together": [
    {"id":"together-svc-early-01","level":"early","profession":"service","title":"The burst pipe, start to finish","scenario":"A pipe has burst above the stockroom: water is coming through the ceiling tiles onto boxed stock, you've killed the stopcock, and the manager is off-site. This one message has to do everything at once — headline, facts, action taken, decision needed — in the length of a text.","task":"Write the complete text: news first, key facts, what's done, the one decision you need.","tips":["BLUF: burst pipe, stockroom, water stopped.","Facts a decision needs: which stock, how wet, plumber's number found.","End on the single question: emergency call-out at $180, yes or no?"],"focus":["structure","clarity"],"placeholder":"Burst pipe above the stockroom — water's stopped, I shut the stopcock at 3:15. Six boxes of paper goods soaked, electricals moved clear and dry. Emergency plumber can come tonight for $180 call-out — yes or no?"},
    {"id":"together-svc-early-02","level":"early","profession":"service","title":"One freezer failure, two audiences","scenario":"The gelato freezer died overnight. By 9am you need two messages: one to your manager (decision-maker, needs facts and options) and one sign for the counter (customers, need cheerful brevity). Same event, opposite registers — writing them back-to-back is the whole skill.","task":"Write both: a 2-sentence manager message and a 1-line customer sign.","tips":["Manager version: temps, stock at risk, the fix options with costs.","Customer version: no gelato today, what to have instead — zero internal detail.","If the two versions sound alike, one of them is wrong."],"focus":["audience","clarity"],"placeholder":"To manager: Gelato freezer failed overnight — cabinet at 9°C, stock unsalvageable (~$300). Repair can come noon ($150) or we borrow the café unit for the weekend. // Sign: No gelato today — but the milkshakes are working overtime."},
    {"id":"together-svc-early-03","level":"early","profession":"service","title":"The 30-second handover","scenario":"Your relief arrived late, your bus leaves in three minutes, and you have five things in your head: a suspected shoplifter's description, a promised callback, low change in till 2, the delivery moved to 4pm, and a broken chair roped off in the café. Thirty seconds. Order and compression decide what survives.","task":"Script the spoken handover: most important first, one breath each, done in 30 seconds.","tips":["Rank before you speak: security issue first, the roped chair can be last.","One sentence per item — headline form, no stories.","Close with the check: 'anything unclear before I run?'"],"focus":["structure","concision"]},
    {"id":"together-svc-early-04","level":"early","profession":"service","title":"The complaint reply with everything in it","scenario":"A guest emailed: her airport pickup never came, she paid $60 for a taxi, and nobody at the desk apologized. She's right on all three. Your reply must do four jobs in six sentences: own it, explain without excusing, make the amend concrete, and give her a reason to come back.","task":"Write the reply email body: apology, one-line explanation, the specific amend, the invitation back.","tips":["Open with ownership of all three failures — itemizing them shows you actually read her email.","Explanation is one line and never the hero: the booking didn't reach our driver.","Amend with numbers: $60 refunded today plus the transfer free next stay.","No 'we take this very seriously' — show it instead with the specifics."],"focus":["audience","impact"],"placeholder":"You're right on every point: the pickup didn't come, it cost you $60, and the desk should have apologized on the spot. The booking never reached our driver — our failure, not yours. I've refunded the $60 to your card today —"},
    {"id":"together-svc-early-05","level":"early","profession":"service","title":"Edit the bloated incident report","scenario":"A coworker drafted the report for yesterday's slip-and-fall and asked you to fix it. It's 300 words: the incident is in the middle, opinions ('the customer seemed fine honestly') mixed with facts, no times, three apologies to whoever reads it. Everything you've practiced, applied to someone else's draft.","task":"List the four edits you'd make, then write the report's new first line.","tips":["Reorder: incident first, response second, detail third.","Strip opinion from fact — 'seemed fine' becomes 'declined first aid, walked unassisted.'","Add the missing precision: times, exact location, names.","Cut the apologies to the reader; reports don't say sorry."],"focus":["precision","structure"],"placeholder":"Edits: 1) incident to line one, 2) facts/opinions separated, 3) exact times added, 4) apologies cut. New first line: At 14:20 a customer slipped on a wet patch near the drinks fridge in aisle 5."},
    {"id":"together-svc-early-06","level":"early","profession":"service","title":"The escalation call, fully loaded","scenario":"A pipe smell in the care client's flat turned out to be a gas leak — engineer's there now, client evacuated safely to the neighbor's. You're calling the agency's on-call manager. She'll make decisions off your two minutes: what happened, what's handled, what you need, in an order she can act on.","task":"Script the call's structure: situation in one line, actions taken, the two decisions you need from her.","tips":["Lead with status: client safe at the neighbor's, gas engineer on site.","Then the timeline in three beats: smell at 2, called 911 at 2:05, evacuated by 2:15.","Close with her part: overnight placement decision, and who calls the family."],"focus":["structure","impact"],"placeholder":"First: Mrs. H is safe at her neighbor's and the gas engineer is on site. Timeline: I smelled gas at 2, called it in at 2:05, had her out by 2:15. I need two things from you —"},
    {"id":"together-svc-early-07","level":"early","profession":"service","title":"The case for making you shift lead","scenario":"The shift-lead role is open and the manager said 'put something in writing by Friday.' Everything converges here: lead with the ask, structure the evidence, be precise about what you've done, anticipate the objection (you're the youngest candidate), and keep it under 150 words.","task":"Write the note: the ask, three evidence points, the objection handled, the close.","tips":["Sentence one is the ask, not your history.","Evidence with numbers: trained four hires, ran 30 closes, zero till discrepancies since March.","Meet 'too young/new' head-on with the one fact that answers it.","End with a next step, not a plea: happy to trial it for a month."],"focus":["structure","impact"],"placeholder":"I'd like to be considered for shift lead. Three things back that up: I've run 30 closes since January with zero till discrepancies, trained our last four hires, and covered every no-show this quarter."},
    {"id":"together-svc-early-08","level":"early","profession":"service","title":"Rolling out the new policy in the chat","scenario":"From Monday, all returns over $50 need a manager sign-off — new till prompt, new form, and the team WILL groan. You're posting the announcement in the staff chat. It needs the headline, the what-changes-for-you, the why in one line, and where questions go — in a message short enough to actually get read.","task":"Write the group-chat post: 4 lines maximum, skimmable, complete.","tips":["Line one: the change and the date, bolded in your head even if not on screen.","Line two: exactly what you do differently at the till.","One line of real why: refund fraud hit us twice last month.","Last line: questions to you by Friday, not into the void."],"focus":["clarity","structure"],"placeholder":"From Monday: returns over $50 need a manager sign-off. At the till, the prompt appears automatically — call whoever's on duty, they tap their code. Why: two fraud hits last month. Questions to me by Friday."},
    {"id":"together-svc-early-09","level":"early","profession":"service","title":"The near-miss that sells its own fix","scenario":"A wheel came off a room-service trolley at the top of the service ramp — it rolled, hit the wall, missed the porter by a step. Nobody hurt, everyone shaken. The report you write can just record it, or it can be built so the fix (trolley inspections, the ramp gate) approves itself. Precision plus persuasion, one document.","task":"Write the 4-sentence report: the near-miss precisely, the cause, what it nearly cost, the fix with price.","tips":["Precision first: which trolley, which ramp, when, how close — 'one step' is the load-bearing detail.","Cause in one line: the wheel's been reported loose since March; no inspection cycle exists.","Then the arithmetic of the ask: monthly checks cost an hour; the alternative was a crushed porter.","Let the gap between those two numbers make the argument."],"focus":["precision","impact"],"placeholder":"At 7:40am trolley 3 lost its front wheel at the top of the service ramp and rolled into the wall — one step from where Danil was standing. That wheel was reported loose in March; there's no inspection cycle to catch it."},
    {"id":"together-svc-early-10","level":"early","profession":"service","title":"The big-day briefing","scenario":"Tomorrow is the street festival — triple footfall, two new starters on shift, a changed floor plan, and a cash-only backup plan if the network dies again. You're running the morning huddle. Five minutes, everything they need, nothing they don't, and they should walk away confident rather than braced.","task":"Script the briefing's skeleton: the signposted opening line and your four headers, one sentence under each.","tips":["Map it first: 'four things, five minutes, then doors.'","Order by when they'll need it: floor plan, then roles, then the if-things-break plan.","New starters hear everything first time — no shorthand today.","End on capability, honestly: 'we've run bigger; stick to the plan.'"],"focus":["structure","audience"],"placeholder":"Four things in five minutes: the new floor plan, who's where, the cash backup, and lunch cover. First — the floor plan changed overnight."},
    {"id":"together-svc-early-11","level":"early","profession":"service","title":"The verdict on the trial","scenario":"The café trialed opening at 6:30 instead of 7 for a month, and the owner wants your read 'in a few lines' — you opened every one of those shifts. You have the numbers (first half-hour averaged 9 customers, $38) and the observation the numbers miss (they're all regulars now, and they're the building site's foremen). Verdict, evidence, recommendation — complete and short.","task":"Write the 3-4 sentence report: verdict first, both kinds of evidence, your recommendation with a condition.","tips":["Verdict in line one — 'keep it, narrowly' is a legitimate verdict.","Give the number AND the thing the number misses: nine customers, but the same nine, daily, with the site running two more years.","Recommend with a review date: keep it, re-check when the site wraps.","Your presence at every shift IS evidence — cite it once."],"focus":["precision","structure"],"placeholder":"Keep the 6:30 open — narrowly, but keep it. The first half-hour averages 9 customers and $38, which barely covers staffing; the part the number misses is it's the same 9 every day: the site foremen, and that site runs two more years."},
    {"id":"together-svc-early-12","level":"early","profession":"service","title":"The file note that stays fair","scenario":"A customer was abusive to your newest team member today — personal comments, refused to leave for ten minutes, other customers visibly uncomfortable. He's a regular and it will likely recur, so you're writing the file note future shifts will rely on. Vent in it and it's useless; vague it and it protects no one.","task":"Write the 3-sentence note: what he did in observable terms, what was done, guidance for next time.","tips":["Observable, quotable behavior — not 'was horrible': raised voice, personal comments about her accent, refused to leave for ten minutes.","Record the response so the next shift knows the precedent: asked to leave, manager notified.","End with instruction, not sentiment: two staff present if he returns, manager called immediately."],"focus":["precision","audience"],"placeholder":"At 4:15 the customer raised his voice at staff, made repeated personal comments about T's accent, and refused to leave for ten minutes after being asked. Duty manager was called and he left before escalation."},
    {"id":"together-svc-early-13","level":"early","profession":"service","title":"The everything-went-wrong day, in five sentences","scenario":"Saturday: the card machines died for an hour, a double-booked function room, one server walked out mid-shift, and — somehow — record takings. The owner returns Monday and wants what happened. Ten minutes of chaos-narration is what she doesn't want; five sentences with a spine is executive summary, learned at a till.","task":"Write the 5-sentence summary: headline, the three problems in order of consequence, the one decision she needs to make.","tips":["Your headline has to hold both truths: record day, three real failures.","One sentence per problem: what broke, what it cost, how it resolved.","The walkout needs a decision (rehire? replace?) — put it last so it sticks.","Chronology is for stories; consequence-order is for summaries."],"focus":["structure","concision"],"placeholder":"Record Saturday — $4,100 — but three things broke on the way. Card machines died 12-1 and we lost maybe six tables to cash-only."},
    {"id":"together-svc-early-14","level":"early","profession":"service","title":"Same news, three channels","scenario":"The salon opens two hours late on Thursday for staff training. That fact needs three forms by tonight: a door sign, a group-chat message to staff, and a voicemail script for the three clients booked at 9am. Same fact; three audiences; three completely different messages.","task":"Write all three: sign (one line), staff post (two lines), client voicemail script (three sentences).","tips":["Sign: the fact and the fix — 'Open at 11 on Thursday' — nothing about training.","Staff: what time to arrive, what to bring, what training covers.","Voicemail: personal, apologetic once, and the rebooking made easy — you call them, not a hotline.","Register check: would each audience recognize the message as being FOR them?"],"focus":["audience","clarity"],"placeholder":"Sign: Thursday we open at 11am — see you then! // Staff: In at 9 Thursday for color training, doors at 11. Bring your kit. // Voicemail: Hi Mrs. Lane, it's Kim from the salon —"},
    {"id":"together-svc-early-15","level":"early","profession":"service","title":"The monthly family summary","scenario":"You've cared for Mr. D all month and his daughter (paying, anxious, overseas) gets a monthly email. This one has to carry: overall he's stable, the walking has declined a little (with your specifics), the new lunch routine works, and you need a decision about the physio referral. Warmth AND precision AND structure — it's all of it at once.","task":"Write the 4-part email body: one-line overall, the change with evidence, the good news, the decision needed.","tips":["Open with the overall read — she scans for alarm first: 'a steady month, one thing to discuss.'","The decline gets specifics, not adjectives: with the frame, 20 meters where 50 was normal.","Good news is evidence too — report the lunch routine win with the same precision.","End with the decision and a deadline: physio referral needs her yes by the 15th."],"focus":["audience","structure"],"placeholder":"A steady month overall, with one thing needing your decision. His walking has dipped: 20 meters with the frame most days, where 50 was normal in May —"},
    {"id":"together-svc-early-16","level":"early","profession":"service","title":"The weekly site report, distilled","scenario":"Your security company wants weekly site reports 'brief but complete' — and your last one was neither: two pages, no verdict, the one genuine incident (a contractor tailgating through the staff entrance, twice) buried under patrol logs. This week's report is your rewrite.","task":"Write the report as: one-line site status, the incident with specifics, one pattern worth watching, done.","tips":["Verdict line first: site secure, one recurring concern.","The incident earns detail — times, description, which door, what you did.","'Nothing happened' patrols compress to one line; they're the background, not the report.","A pattern flagged early ('same contractor, both times') is what makes reports worth reading."],"focus":["precision","concision"],"placeholder":"Site status: secure, one recurring concern. A contractor tailgated through the staff entrance twice this week (Tue 7:42am, Thu 7:50am, same individual, hi-vis, no badge shown) — challenged and badged-in properly the second time."},
    {"id":"together-svc-early-17","level":"early","profession":"service","title":"The equipment pitch, complete","scenario":"You want a second vacuum for the night crew — the case has everything you've practiced: the timed evidence (an hour lost nightly to sharing), the objection you can predict ('there's no budget this quarter'), and a proposal that has to fit in the supervisor's two-minute doorway attention span. Build the whole thing.","task":"Write the 4-5 sentence pitch: ask, evidence, objection answered, tiny next step.","tips":["Ask first: a second vacuum for nights, about $220.","Evidence you measured yourself: sharing one costs us an hour a night — that's 20+ hours a month.","Answer the budget line before she says it: at our hourly rate it pays for itself in a fortnight.","Shrink the next step: approve it and I'll have three quotes to you by Friday."],"focus":["structure","impact"],"placeholder":"I'm asking for a second vacuum for the night crew — about $220. Sharing one costs us roughly an hour every night waiting and ferrying between floors; that's twenty hours a month."},
    {"id":"together-svc-early-18","level":"early","profession":"service","title":"The apology that keeps the client","scenario":"Your cleaning company missed Mrs. Aldana's scheduled Friday clean — no call, no show, a scheduling error your office made. She hosted family Saturday with the house uncleaned and she's rightly furious. The message you send has to own it fully, fix it concretely, and show it won't recur — because 'sorry' alone keeps no clients.","task":"Write the message: ownership without excuses, the specific make-good, the prevention step, all in 4 sentences.","tips":["Own the whole thing including the silence: missing the clean was bad; not calling was worse.","The make-good matches the harm: this week's clean free, priority Friday slot going forward.","Prevention in one concrete line: your slot is now double-confirmed by text each Thursday.","No 'due to a scheduling error' passive fog — 'our office booked it wrong.'"],"focus":["audience","impact"],"placeholder":"We failed you twice on Friday: our office booked your clean wrong, and nobody called to warn you — before your family visit, of all weekends. This week's clean is free, and it's done today if you'll have us."},
    {"id":"together-svc-early-19","level":"early","profession":"service","title":"The first-day welcome brief","scenario":"A new starter arrives in twenty minutes and you're doing her welcome brief. Day one is a firehose; your job is choosing the five things she needs before lunch — not the forty in the manual. Fire exits, her buddy, where lunch happens, the one till rule that matters, who to ask. Audience-first thinking, applied to your own team.","task":"Script the 5-line brief in the order that serves HER morning, ending with the safety net.","tips":["Her morning, chronologically: coat, buddy, first task — before policies.","One rule today, not ten: never open the till without your own code.","The safety net line matters most: 'any question at all — me, all day; there are no stupid ones this week.'","Everything else has a place: 'the rest lives in the folder, and nobody expects you to know it.'"],"focus":["audience","concision"]},
    {"id":"together-svc-early-20","level":"early","profession":"service","title":"The holiday handover pack","scenario":"You're away for two weeks and three different people will cover your patch — the care rounds, the supply orders, the family contacts. Whatever you don't write down becomes a 7am phone call to your holiday. The handover needs everything, structured so each person finds THEIR part in ten seconds.","task":"Design the handover's structure: the three sections by owner, and write the top-priority line for each.","tips":["Organize by who does it, not by topic — each cover person reads only their block.","Within each block: the must-not-miss item first, flagged.","Dates and numbers in every line — 'order Tuesday' not 'order weekly.'","End with the escalation line: what actually justifies calling you."],"focus":["structure","clarity"],"placeholder":"FOR MARIA (care rounds): Mrs. H's meds changed on the 3rd — new dosette arrives Tuesday, pharmacy number below. FOR JAKE (supplies): order Tuesday by 2pm —"},
    {"id":"together-svc-early-21","level":"early","profession":"service","title":"The bad review, answered to the owner's face","scenario":"A one-star review names Saturday night: 'waited 50 minutes, wrong order, waitress didn't care.' You were that waitress. The owner reads it aloud and looks at you. The truthful answer has all three parts: what's accurate (the wait — kitchen was down a chef), what isn't (you comped her dessert, which the review omits), and what you'd change. Composed, factual, non-defensive — under pressure, this is the whole course.","task":"Give the 3-4 sentence spoken response covering all three parts in that order.","tips":["Concede the true part first and precisely: the 50 minutes is real; we were down a chef.","Correct the record without heat: the missing fact, stated once — I comped the dessert and checked twice.","Defensive tone loses even when the facts win — keep it autopsy-calm.","Close forward: the one change that prevents the next one."],"focus":["clarity","impact"],"placeholder":"The 50-minute wait is accurate — we lost a chef that night at 6. What the review leaves out: I comped her dessert and checked on the table twice, which is also on the till record. The fix that matters —"},
    {"id":"together-svc-early-22","level":"early","profession":"service","title":"Selling your checklist at the huddle","scenario":"You built a five-line closing checklist after last month's freezer incident, your manager approved it, and now you have ninety seconds at the huddle to get eight tired colleagues to actually adopt it. Structure for the listening ear, persuasion for the skeptics, brevity because it's 4pm. This is your idea and your ninety seconds.","task":"Script the pitch: the hook, what it is, the objection you'll pre-empt ('more paperwork'), the start date.","tips":["Hook with the shared memory, one line: we all remember the freezer morning.","Describe the cost honestly: five ticks, ninety seconds, pen's on a string.","Pre-empt the groan: it's not paperwork for head office — no one sees it but us; it's proof-we're-covered.","Land the start: tonight, my close, I'll run it first."],"focus":["audience","impact"],"placeholder":"Ninety seconds on the new close list — because none of us wants another freezer morning. It's five ticks at the door, pen's on a string, nobody above this room ever reads it."},
    {"id":"together-svc-early-23","level":"early","profession":"service","title":"The altercation report, court-ready","scenario":"Two customers fought by the returns desk; you separated them, one has a cut lip, police took statements, and now the full incident report is yours to write. This is where everything must hold at once: exact times and observables (it may be read in court), clean structure (four sections), zero opinion, and the actions taken — including yours — in active voice.","task":"Write the report's four section headers and the complete first section.","tips":["Sections: incident, persons involved, actions taken, follow-up required.","Court test on every line: observed, not inferred — 'shouted and pushed' not 'was aggressive.'","Times to the minute, positions to the fixture: 'by the returns desk, north side.'","Your own actions in first person active: 'I stepped between them at 15:12.'"],"focus":["precision","structure"],"placeholder":"INCIDENT: At 15:10 on the 12th, two male customers began shouting at the returns desk, north side. At 15:11 the taller man pushed the other into the queue barrier —"},
    {"id":"together-svc-early-24","level":"early","profession":"service","title":"The colleague's error, reported right","scenario":"You've discovered a coworker gave a bride's deposit refund to the wrong account three days ago — an honest slip with real consequences: the bride's calling tomorrow and the money's gone to a stranger. Telling the manager needs everything at once: headline first, facts precise, no editorial on the coworker, and the recovery options ready.","task":"Write the message: the problem in line one, the trail with dates, the two recovery options, coworker treated fairly.","tips":["Lead with the situation, not the person: 'a deposit refund went to the wrong account' — the who comes later and neutrally.","The paper trail, precise: $500, sent Tuesday, sort code one digit off, bride calls tomorrow.","Options ready: bank recall (started today, 5-10 days) or refund her now and recover in parallel.","Write it knowing the coworker might read it — that's the fairness test."],"focus":["precision","audience"],"placeholder":"A deposit refund has gone to the wrong account and the client calls tomorrow — we need to pick a fix today. The trail: $500 to the Okonkwo wedding, sent Tuesday, one digit off in the sort code."},
    {"id":"together-svc-early-25","level":"early","profession":"service","title":"Choose the channel, then nail it","scenario":"It's 9:40pm, you're closing alone, and you've just found a rat dropping trail behind the flour shelf. Tomorrow's baker arrives at 5am and bakes unless stopped; environmental health rules are strict; your manager's phone is on do-not-disturb overnight. First decision: text, call, note, or all three? Then: the message itself. The channel choice IS part of the communication.","task":"Name your channel choice with a one-line reason, then write the message for it.","tips":["Work back from who must act first: the 5am baker must not bake — reach HIM directly, then the manager.","Urgency test for channels: if it can't wait for a read-receipt, it's a call; if evidence matters, add a photo.","Whatever you choose, the message still leads with the point: evidence of pests, don't prep food.","Belt and braces is legitimate: text now, note taped to the flour shelf, manager's voicemail."],"focus":["clarity","impact"],"placeholder":"Channel: text the baker directly now (he must act first at 5am), plus a taped note on the shelf and a voicemail for the manager. Text: STOP before you prep — found rat droppings behind the flour shelf at 9:40pm, photos attached. Nothing gets baked until Dev clears it."}
  ],
};
